export type OnboardingState = "active" | "summary_pending" | "complete";
export type OnboardingAction = "finalize_onboarding" | "continue_onboarding";
export type ObservationSeverity = "info" | "warning" | "conflict";
export type ObservationStatus = "open" | "acknowledged" | "resolved";

export const OBSERVATION_TYPES = ["contradiction", "duplication", "missing", "deprecated", "pattern", "anomaly", "validation", "error"] as const;
export type ObservationType = (typeof OBSERVATION_TYPES)[number];

export type ObservationSummary = {
  id: string;
  text: string;
  severity: ObservationSeverity;
  status: ObservationStatus;
  category?: EntityCategory;
  observationType?: ObservationType;
  sourceAgent: string;
  createdAt: string;
};

export const SUGGESTION_CATEGORIES = ["optimization", "risk", "opportunity", "conflict", "missing", "pivot"] as const;
export type SuggestionCategory = (typeof SUGGESTION_CATEGORIES)[number];

export const SUGGESTION_STATUSES = ["pending", "accepted", "dismissed", "deferred", "converted"] as const;
export type SuggestionStatus = (typeof SUGGESTION_STATUSES)[number];

export type SuggestionSummary = {
  id: string;
  text: string;
  category: SuggestionCategory;
  rationale: string;
  suggestedBy: string;
  confidence: number;
  status: SuggestionStatus;
  createdAt: string;
};

import type { RecordId } from "surrealdb";
import type { BrainAction } from "../oauth/types";
import type { PolicyTraceEntry } from "../policy/types";

export type { PolicyTraceEntry } from "../policy/types";

// --- Intent Status (state machine states) ---

export type IntentStatus =
  | "draft"
  | "pending_auth"
  | "pending_veto"
  | "authorized"
  | "executing"
  | "completed"
  | "vetoed"
  | "failed";

// --- Action Specification ---

export type ActionSpec = {
  provider: string;
  action: string;
  params?: Record<string, unknown>;
};

// --- Budget Limit ---

export type BudgetLimit = {
  amount: number;
  currency: string;
};

// --- Evaluation Result ---

export type EvaluationResult = {
  decision: "APPROVE" | "REJECT";
  risk_score: number;
  reason: string;
};

// --- Routing Decision (discriminated union) ---

export type RoutingDecision =
  | { route: "auto_approve" }
  | { route: "veto_window"; expires_at: Date }
  | { route: "reject"; reason: string };

// --- Intent Record ---

export type IntentRecord = {
  id: RecordId<"intent", string>;
  goal: string;
  reasoning: string;
  status: IntentStatus;
  priority: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  evaluation?: EvaluationResult & {
    evaluated_at: Date;
    policy_only: boolean;
    policy_trace?: PolicyTraceEntry[];
    human_veto_required?: boolean;
  };
  veto_expires_at?: Date;
  veto_reason?: string;
  error_reason?: string;
  authorization_details?: BrainAction[];
  dpop_jwk_thumbprint?: string;
  token_issued_at?: Date;
  token_expires_at?: Date;
  embedding?: number[];
  trace_id: RecordId<"trace", string>;
  requester: RecordId<"identity", string>;
  workspace: RecordId<"workspace", string>;
  created_at: Date;
  updated_at?: Date;
  expiry?: Date;
};

