 14→export async function createObservation(input: {
 15→  surreal: Surreal;
 16→  workspaceRecord: RecordId<"workspace", string>;
 17→  text: string;
 18→  severity: ObservationSeverity;
 19→  category?: EntityCategory;
 20→  observationType?: ObservationType;
 21→  sourceAgent: string;
 22→  now: Date;
 23→  sourceMessageRecord?: RecordId<"message", string>;
 24→  sourceSessionRecord?: RecordId<"agent_session", string>;
 25→  relatedRecords?: ObserveTargetRecord[];
 26→  embedding?: number[];
 27→  confidence?: number;
 28→  evidenceRefs?: RecordId[];
 29→  verified?: boolean;
 30→  source?: string;
 31→}): Promise<ObservationRecord> {
 32→  const observationRecord = new RecordId("observation", randomUUID());
 33→
 34→  await input.surreal.create(observationRecord).content({
 35→    text: input.text,
 36→    severity: input.severity,
 37→    status: "open",
 38→    ...(input.category ? { category: input.category } : {}),
 39→    ...(input.observationType ? { observation_type: input.observationType } : {}),
 40→    source_agent: input.sourceAgent,
 41→    workspace: input.workspaceRecord,
 42→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
 43→    ...(input.sourceSessionRecord ? { source_session: input.sourceSessionRecord } : {}),
 44→    ...(input.embedding ? { embedding: input.embedding } : {}),
 45→    ...(input.confidence !== undefined ? { confidence: input.confidence } : {}),
 46→    ...(input.evidenceRefs && input.evidenceRefs.length > 0 ? { evidence_refs: input.evidenceRefs } : {}),
 47→    ...(input.verified !== undefined ? { verified: input.verified } : {}),
 48→    ...(input.source ? { source: input.source } : {}),
 49→    created_at: input.now,
 50→    updated_at: input.now,
 51→  });
 52→
 53→  // Create observes edges to related entities
 54→  const targets: ObserveTargetRecord[] = input.relatedRecords ?? [];
 55→
 56→  for (const target of targets) {
 57→    await input.surreal
 58→      .relate(observationRecord, new RecordId("observes", randomUUID()), target, {
 59→        added_at: input.now,
 60→      })
 61→      .output("after");
 62→  }
 63→
 64→  return observationRecord;
 65→}
