164→// ---------------------------------------------------------------------------
165→// Pure comparison: decision confirmation/supersession verification
166→// ---------------------------------------------------------------------------
167→
168→export function compareDecisionConfirmation(
169→  signals: DecisionSignals,
170→): VerificationResult {
171→  if (signals.status === "confirmed") {
172→    if (signals.completedTaskCount === 0) {
173→      return {
174→        verdict: "inconclusive",
175→        severity: "info",
176→        verified: false,
177→        text: `Decision confirmed: "${signals.summary}". No completed tasks in workspace.`,
178→      };
179→    }
180→
181→    return {
182→      verdict: "match",
183→      severity: "info",
184→      verified: true,
185→      text: `Decision confirmed: "${signals.summary}". ${signals.completedTaskCount} completed task(s) in workspace available for alignment review.`,
186→    };
187→  }
188→
189→  if (signals.status === "superseded") {
190→    if (signals.completedTaskCount === 0) {
191→      return {
192→        verdict: "inconclusive",
193→        severity: "info",
194→        verified: false,
195→        text: `Decision superseded: "${signals.summary}". No completed tasks found that may be affected.`,
196→      };
197→    }
198→
199→    return {
200→      verdict: "mismatch",
201→      severity: "warning",
202→      verified: false,
203→      text: `Decision superseded: "${signals.summary}". ${signals.completedTaskCount} completed task(s) in workspace may reference an outdated decision. Review for staleness.`,
204→    };
205→  }
206→
207→  return {
208→    verdict: "inconclusive",
209→    severity: "info",
210→    verified: false,
211→    text: `Decision in unexpected status '${signals.status}': "${signals.summary}"`,
212→  };
213→}
