  1→/**
  2→ * Verification pipeline: pure core functions for claim-vs-reality comparison.
  3→ *
  4→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> createObservation
  5→ *
  6→ * All functions in this module are pure (no IO). The effect shell lives in observer-route.ts.
  7→ */
  8→
  9→import type { GatherSignalsResult } from "./external-signals";
 10→import type { LlmVerdict } from "./schemas";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Types
 14→// ---------------------------------------------------------------------------
 15→
 16→export type Verdict = "match" | "mismatch" | "inconclusive";
 17→
 18→export type VerdictSource = "llm" | "deterministic_fallback" | "github" | "peer_review" | "none";
 19→
 20→export type VerificationResult = {
 21→  verdict: Verdict;
 22→  severity: "info" | "warning" | "conflict";
 23→  verified: boolean;
 24→  text: string;
 25→  source?: string;
 26→  confidence?: number;
 27→  evidenceRefs?: string[];
 28→  observationType?: "contradiction" | "validation";
 29→};
 30→
 31→export type IntentStatus = "completed" | "failed" | string;
 32→
 33→export type IntentSignals = {
 34→  status: IntentStatus;
 35→  goal: string;
 36→  hasTrace: boolean;
 37→};
 38→
 39→export type DecisionStatus = "confirmed" | "superseded" | string;
 40→
 41→export type DecisionSignals = {
 42→  status: DecisionStatus;
 43→  summary: string;
 44→  completedTaskCount: number;
 45→};
 46→
 47→export type ObservationPeerReviewSignals = {
 48→  originalText: string;
 49→  originalSeverity: "info" | "warning" | "conflict";
 50→  sourceAgent: string;
 51→  linkedEntityCount: number;
 52→};
 53→
 54→// ---------------------------------------------------------------------------
 55→// Pure comparison: claim vs reality for task completion
 56→// ---------------------------------------------------------------------------
 57→
 58→export function compareTaskCompletion(
 59→  signalsResult: GatherSignalsResult,
 60→): VerificationResult {
 61→  // No commits linked -> inconclusive
 62→  if (!signalsResult.hasCommits || signalsResult.signals.length === 0) {
 63→    return {
 64→      verdict: "inconclusive",
 65→      severity: "info",
 66→      verified: false,
 67→      text: "Unable to verify task completion: no external signals (commits or CI) found for this task.",
 68→    };
 69→  }
 70→
 71→  // Check CI status across all signals
 72→  const ciSignals = signalsResult.signals.filter(
 73→    (signal) => signal.ciStatus !== "unknown",
 74→  );
 75→
 76→  // All signals unknown -> inconclusive
 77→  if (ciSignals.length === 0) {
 78→    return {
 79→      verdict: "inconclusive",
 80→      severity: "info",
 81→      verified: false,
 82→      text: "Unable to verify task completion: CI status unavailable for linked commits.",
 83→      source: signalsResult.signals[0]?.source,
 84→    };
 85→  }
 86→
 87→  // Any failing CI -> mismatch
 88→  const failingSignals = ciSignals.filter(
 89→    (signal) => signal.ciStatus === "failure",
 90→  );
 91→
 92→  if (failingSignals.length > 0) {
 93→    const failingShas = failingSignals.map((s) => s.sha.slice(0, 8)).join(", ");
 94→    return {
 95→      verdict: "mismatch",
 96→      severity: "conflict",
 97→      verified: false,
 98→      text: `Task marked as completed but CI is failing for commit(s): ${failingShas}. Claim does not match reality.`,
 99→      source: failingSignals[0]?.source,
100→    };
101→  }
102→
103→  // Any pending CI -> inconclusive (not verified yet)
104→  const pendingSignals = ciSignals.filter(
105→    (signal) => signal.ciStatus === "pending",
106→  );
107→
108→  if (pendingSignals.length > 0) {
109→    return {
110→      verdict: "inconclusive",
111→      severity: "info",
112→      verified: false,
113→      text: "Task completion verification pending: CI checks still running.",
114→      source: pendingSignals[0]?.source,
115→    };
116→  }
117→
118→  // All passing -> match
119→  const source = ciSignals[0]?.source;
120→  return {
121→    verdict: "match",
122→    severity: "info",
123→    verified: true,
124→    text: "Task completion verified: all linked CI checks are passing.",
125→    source,
126→  };
127→}
128→
129→// ---------------------------------------------------------------------------
130→// Pure comparison: intent completion verification
131→// ---------------------------------------------------------------------------
132→
133→export function compareIntentCompletion(
134→  signals: IntentSignals,
135→): VerificationResult {
136→  if (signals.status === "completed") {
137→    return {
138→      verdict: "match",
139→      severity: "info",
140→      verified: true,
141→      text: `Intent completed successfully: ${signals.goal}`,
142→      source: signals.hasTrace ? "trace" : undefined,
143→    };
144→  }
145→
146→  if (signals.status === "failed") {
147→    return {
148→      verdict: "mismatch",
149→      severity: "warning",
150→      verified: false,
151→      text: `Intent failed: ${signals.goal}`,
152→      source: signals.hasTrace ? "trace" : undefined,
153→    };
154→  }
155→
156→  return {
157→    verdict: "inconclusive",
158→    severity: "info",
159→    verified: false,
160→    text: `Intent in unexpected status '${signals.status}': ${signals.goal}`,
161→  };
162→}
