215→// ---------------------------------------------------------------------------
216→// Pure comparison: observation peer review
217→// ---------------------------------------------------------------------------
218→
219→export function compareObservationPeerReview(
220→  signals: ObservationPeerReviewSignals,
221→): VerificationResult {
222→  if (signals.linkedEntityCount === 0) {
223→    return {
224→      verdict: "inconclusive",
225→      severity: "info",
226→      verified: false,
227→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". No linked entities found to cross-check this claim.`,
228→    };
229→  }
230→
231→  // When linked entities exist, cross-check severity
232→  if (signals.originalSeverity === "conflict") {
233→    return {
234→      verdict: "match",
235→      severity: "warning",
236→      verified: false,
237→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Cross-checked against ${signals.linkedEntityCount} linked entity(ies). Conflict claim requires human review.`,
238→    };
239→  }
240→
241→  if (signals.originalSeverity === "warning") {
242→    return {
243→      verdict: "match",
244→      severity: "info",
245→      verified: true,
246→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Cross-checked against ${signals.linkedEntityCount} linked entity(ies). Warning acknowledged.`,
247→    };
248→  }
249→
250→  return {
251→    verdict: "match",
252→    severity: "info",
253→    verified: true,
254→    text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Cross-checked against ${signals.linkedEntityCount} linked entity(ies).`,
255→  };
256→}
257→
258→export function compareCommitStatus(
259→  signalsResult: GatherSignalsResult,
260→): VerificationResult {
261→  // No CI signals available -> inconclusive
262→  if (signalsResult.signals.length === 0) {
263→    return {
264→      verdict: "inconclusive",
265→      severity: "info",
266→      verified: false,
267→      text: "Commit recorded: no CI status available for verification.",
268→    };
269→  }
270→
271→  const ciSignals = signalsResult.signals.filter(
272→    (signal) => signal.ciStatus !== "unknown",
273→  );
274→
275→  if (ciSignals.length === 0) {
276→    return {
277→      verdict: "inconclusive",
278→      severity: "info",
279→      verified: false,
280→      text: "Commit recorded: CI status unavailable.",
281→      source: signalsResult.signals[0]?.source,
282→    };
283→  }
284→
285→  const failingSignals = ciSignals.filter(
286→    (signal) => signal.ciStatus === "failure",
287→  );
288→
289→  if (failingSignals.length > 0) {
290→    return {
291→      verdict: "mismatch",
292→      severity: "warning",
293→      verified: false,
294→      text: `Commit has failing CI: ${failingSignals.map((s) => s.sha.slice(0, 8)).join(", ")}`,
295→      source: failingSignals[0]?.source,
296→    };
297→  }
298→
299→  const pendingSignals = ciSignals.filter(
300→    (signal) => signal.ciStatus === "pending",
301→  );
302→
303→  if (pendingSignals.length > 0) {
304→    return {
305→      verdict: "inconclusive",
306→      severity: "info",
307→      verified: false,
308→      text: "Commit verification pending: CI checks still running.",
309→      source: pendingSignals[0]?.source,
310→    };
311→  }
312→
313→  return {
314→    verdict: "match",
315→    severity: "info",
316→    verified: true,
317→    text: "Commit verified: all CI checks passing.",
318→    source: ciSignals[0]?.source,
319→  };
320→}
