322→// ---------------------------------------------------------------------------
323→// LLM verdict logic: skip optimization, confidence threshold, fallback
324→// ---------------------------------------------------------------------------
325→
326→/**
327→ * Determines whether the LLM should be invoked for verification.
328→ *
329→ * Skip conditions (all must be true):
330→ *   - workspace.settings.observer_skip_deterministic is true (or absent = default true)
331→ *   - deterministic verdict is "match"
332→ *   - CI is passing (source includes "github" or verified is true)
333→ */
334→export function shouldSkipLlm(
335→  deterministicVerdict: VerificationResult,
336→  skipDeterministic?: boolean,
337→): boolean {
338→  // Default to true when absent
339→  const skipEnabled = skipDeterministic ?? true;
340→
341→  if (!skipEnabled) return false;
342→
343→  return deterministicVerdict.verdict === "match" && deterministicVerdict.verified === true;
344→}
345→
346→/**
347→ * Applies confidence threshold and fallback to produce a final verification result.
348→ *
349→ * - LLM confidence < 0.5 → downgrade to inconclusive, severity=info
350→ * - LLM verdict=mismatch + confidence >= 0.5 → severity=conflict, type=contradiction
351→ * - LLM verdict=match + confidence >= 0.5 → severity=info, verified=true
352→ * - LLM failure (undefined) → fallback to deterministic with source=deterministic_fallback
353→ */
354→export function applyLlmVerdict(
355→  deterministicVerdict: VerificationResult,
356→  llmVerdict: LlmVerdict | undefined,
357→): VerificationResult {
358→  // Fallback: LLM failed or was not called
359→  if (!llmVerdict) {
360→    return {
361→      ...deterministicVerdict,
362→      source: "deterministic_fallback",
363→    };
364→  }
365→
366→  // Low confidence → downgrade to inconclusive
367→  if (llmVerdict.confidence < 0.5) {
368→    return {
369→      verdict: "inconclusive",
370→      severity: "info",
371→      verified: false,
372→      text: llmVerdict.reasoning,
373→      source: "llm",
374→      confidence: llmVerdict.confidence,
375→      evidenceRefs: llmVerdict.evidence_refs,
376→    };
377→  }
378→
379→  // Mismatch → contradiction
380→  if (llmVerdict.verdict === "mismatch") {
381→    return {
382→      verdict: "mismatch",
383→      severity: "conflict",
384→      verified: false,
385→      text: llmVerdict.reasoning,
386→      source: "llm",
387→      confidence: llmVerdict.confidence,
388→      evidenceRefs: llmVerdict.evidence_refs,
389→      observationType: "contradiction",
390→    };
391→  }
392→
393→  // Match → verified
394→  if (llmVerdict.verdict === "match") {
395→    return {
396→      verdict: "match",
397→      severity: "info",
398→      verified: true,
399→      text: llmVerdict.reasoning,
400→      source: "llm",
401→      confidence: llmVerdict.confidence,
402→      evidenceRefs: llmVerdict.evidence_refs,
403→      observationType: "validation",
404→    };
405→  }
406→
407→  // Inconclusive from LLM
408→  return {
409→    verdict: "inconclusive",
410→    severity: "info",
411→    verified: false,
412→    text: llmVerdict.reasoning,
413→    source: "llm",
414→    confidence: llmVerdict.confidence,
415→    evidenceRefs: llmVerdict.evidence_refs,
416→  };
417→}
