121→
122→async function queryConfirmedDecisions(
123→  surreal: Surreal,
124→  workspaceRecord: RecordId<"workspace", string>,
125→): Promise<ConfirmedDecision[]> {
126→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
127→    `SELECT id, summary, rationale, created_at FROM decision
128→     WHERE workspace = $ws AND status = "confirmed"
129→     ORDER BY created_at DESC
130→     LIMIT 50;`,
131→    { ws: workspaceRecord },
132→  );
133→  return rows ?? [];
134→}
135→
136→async function queryCompletedTasks(
137→  surreal: Surreal,
138→  workspaceRecord: RecordId<"workspace", string>,
139→): Promise<CompletedTask[]> {
140→  const [rows] = await surreal.query<[CompletedTask[]]>(
141→    `SELECT id, title, description, updated_at FROM task
142→     WHERE workspace = $ws AND status IN ["completed", "done"]
143→     ORDER BY updated_at DESC
144→     LIMIT 50;`,
145→    { ws: workspaceRecord },
146→  );
147→  return rows ?? [];
148→}
149→
150→async function queryStaleBlockedTasks(
151→  surreal: Surreal,
152→  workspaceRecord: RecordId<"workspace", string>,
153→): Promise<StaleBlockedTask[]> {
154→  const thresholdDate = new Date(
155→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
156→  );
157→
158→  const [rows] = await surreal.query<
159→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
160→  >(
161→    `SELECT id, title, description, updated_at FROM task
162→     WHERE workspace = $ws
163→       AND status = "blocked"
164→       AND updated_at < $threshold
165→     ORDER BY updated_at ASC
166→     LIMIT 50;`,
167→    { ws: workspaceRecord, threshold: thresholdDate },
168→  );
169→
170→  return (rows ?? []).map((row) => {
171→    const updatedAt = new Date(row.updated_at);
172→    const daysBlocked = Math.floor(
173→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
174→    );
175→    return { ...row, daysBlocked };
176→  });
177→}
178→
179→async function queryStatusDriftTasks(
180→  surreal: Surreal,
181→  workspaceRecord: RecordId<"workspace", string>,
182→): Promise<StatusDriftTask[]> {
183→  // Two-step approach: first find completed tasks with dependencies,
184→  // then filter for incomplete dependencies in application code
185→  const [rows] = await surreal.query<[Array<{
186→    id: RecordId<"task">;
187→    title: string;
188→    status: string;
189→    dep_ids: RecordId<"task">[];
190→    dep_titles: string[];
191→    dep_statuses: string[];
192→  }>]>(
193→    `SELECT
194→       id, title, status,
195→       ->depends_on->task.id AS dep_ids,
196→       ->depends_on->task.title AS dep_titles,
197→       ->depends_on->task.status AS dep_statuses
198→     FROM task
199→     WHERE workspace = $ws
200→       AND status IN ["completed", "done"]
201→       AND array::len(->depends_on->task) > 0
202→     LIMIT 50;`,
203→    { ws: workspaceRecord },
204→  );
205→
206→  return (rows ?? []).flatMap((row) => {
207→    const depIds = row.dep_ids ?? [];
208→    const depTitles = row.dep_titles ?? [];
209→    const depStatuses = row.dep_statuses ?? [];
210→
211→    const drifts: StatusDriftTask[] = [];
212→    for (let i = 0; i < depIds.length; i++) {
213→      const depStatus = depStatuses[i];
214→      if (depStatus !== "completed" && depStatus !== "done") {
215→        drifts.push({
216→          id: row.id,
217→          title: row.title,
218→          status: row.status,
219→          dependency: {
220→            id: depIds[i],
221→            title: depTitles[i],
222→            status: depStatus,
223→          },
224→        });
225→      }
226→    }
227→    return drifts;
228→  });
229→}
