235→/**
236→ * Queries existing open observer observations linked to a specific entity.
237→ * Used for entity-level dedup -- if the observer already has an open observation
238→ * on this entity, we skip creating another.
239→ */
240→// Static query map: one pre-built query string per allowed table, eliminating
241→// dynamic interpolation at the call site (prevents SurrealQL injection).
242→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
243→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation", "objective"].map(
244→    (table) => [
245→      table,
246→      `SELECT text, severity, status FROM observation
247→       WHERE workspace = $ws
248→         AND source_agent = "observer_agent"
249→         AND status IN ["open", "acknowledged"]
250→         AND ->observes->${table}.id CONTAINS $entity
251→       LIMIT 20;`,
252→    ],
253→  ),
254→);
255→
256→export async function queryExistingObserverObservationsForEntity(
257→  surreal: Surreal,
258→  workspaceRecord: RecordId<"workspace", string>,
259→  entityRecord: RecordId<string, string>,
260→): Promise<Array<{ text: string; severity: string; status: string }>> {
261→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
262→  if (!query) {
263→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
264→  }
265→
266→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
267→    query,
268→    { ws: workspaceRecord, entity: entityRecord },
269→  );
270→  return rows ?? [];
271→}
272→
273→// ---------------------------------------------------------------------------
274→// Deduplication
275→// ---------------------------------------------------------------------------
276→
277→export type ExistingObservation = {
278→  text: string;
279→  severity: string;
280→  status: string;
281→};
282→
283→export function isAlreadyObserved(
284→  existingObservations: ExistingObservation[],
285→  newText: string,
286→  entityId?: string,
287→): boolean {
288→  const normalizedNew = newText.toLowerCase();
289→
290→  return existingObservations.some((obs) => {
291→    if (obs.status === "resolved") return false;
292→
293→    // When entity ID is available, require it to appear in the existing text
294→    // so observations about different entities are never considered duplicates
295→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
296→      return false;
297→    }
298→
299→    const normalizedExisting = obs.text.toLowerCase();
300→    // Check if the core issue is already covered using a meaningful prefix
301→    const prefixLen = Math.min(80, normalizedNew.length);
302→    return (
303→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
304→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
305→    );
306→  });
307→}
308→
309→// ---------------------------------------------------------------------------
310→// Coherence queries (deterministic, no LLM needed)
311→// ---------------------------------------------------------------------------
312→
313→/**
314→ * Finds confirmed decisions older than the coherence threshold with no
315→ * implementing task or commit (via implemented_by edges).
316→ */
317→export async function queryOrphanedDecisions(
318→  surreal: Surreal,
319→  workspaceRecord: RecordId<"workspace", string>,
320→): Promise<OrphanedDecision[]> {
321→  const thresholdDate = new Date(
322→    Date.now() - COHERENCE_AGE_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
323→  );
324→
325→  const [rows] = await surreal.query<[OrphanedDecision[]]>(
326→    `SELECT id, summary, created_at FROM decision
327→     WHERE workspace = $ws
328→       AND status = "confirmed"
329→       AND created_at < $threshold
330→       AND array::len(<-implemented_by<-git_commit) = 0
331→       AND array::len(<-implemented_by<-pull_request) = 0
332→     ORDER BY created_at ASC
333→     LIMIT 50;`,
334→    { ws: workspaceRecord, threshold: thresholdDate },
335→  );
336→  return rows ?? [];
337→}
338→
339→/**
340→ * Finds active objectives older than the coherence threshold with no
341→ * supporting intents (via supports edges).
342→ */
343→export async function queryStaleObjectives(
344→  surreal: Surreal,
345→  workspaceRecord: RecordId<"workspace", string>,
346→): Promise<StaleObjective[]> {
347→  const thresholdDate = new Date(
348→    Date.now() - COHERENCE_AGE_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
349→  );
350→
351→  const [rows] = await surreal.query<[StaleObjective[]]>(
352→    `SELECT id, title, created_at FROM objective
353→     WHERE workspace = $ws
354→       AND status = "active"
355→       AND created_at < $threshold
356→       AND array::len(<-supports<-intent) = 0
357→     ORDER BY created_at ASC
358→     LIMIT 50;`,
359→    { ws: workspaceRecord, threshold: thresholdDate },
360→  );
361→  return rows ?? [];
362→}
363→
364→/**
365→ * Finds completed tasks older than the coherence threshold that have no
366→ * linked decision records -- neither directly via implemented_by edges
367→ * nor indirectly via shared feature/project (belongs_to edges).
368→ *
369→ * Deterministic graph query, no LLM needed.
370→ */
371→export async function queryImplementationsWithoutDecisions(
372→  surreal: Surreal,
373→  workspaceRecord: RecordId<"workspace", string>,
374→): Promise<ImplementationWithoutDecision[]> {
375→  const thresholdDate = new Date(
376→    Date.now() - COHERENCE_AGE_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
377→  );
378→
379→  // Two-step approach:
380→  // 1. Find completed tasks older than threshold
381→  // 2. Filter out tasks that have decision links (direct or via feature/project)
382→  const [rows] = await surreal.query<[ImplementationWithoutDecision[]]>(
383→    `SELECT id, title, created_at FROM task
384→     WHERE workspace = $ws
385→       AND status IN ["completed", "done"]
386→       AND created_at < $threshold
387→       AND array::len(<-implemented_by<-decision) = 0
388→       AND array::len(->belongs_to->feature<-belongs_to<-decision) = 0
389→       AND array::len(->belongs_to->project<-belongs_to<-decision) = 0
390→     ORDER BY created_at ASC
391→     LIMIT 50;`,
392→    { ws: workspaceRecord, threshold: thresholdDate },
393→  );
394→
395→  return rows ?? [];
396→}
397→
398→/**
399→ * Runs coherence scans: detects orphaned decisions and stale objectives,
400→ * creates observations for disconnected patterns.
401→ *
402→ * Deterministic -- no LLM filtering needed.
403→ */
404→export async function runCoherenceScans(
405→  surreal: Surreal,
406→  workspaceRecord: RecordId<"workspace", string>,
407→): Promise<CoherenceScanResult> {
408→  const result: CoherenceScanResult = {
409→    orphaned_decisions_found: 0,
410→    stale_objectives_found: 0,
411→    implementations_without_decisions_found: 0,
412→    observations_created: 0,
413→  };
414→
415→  // Load existing observations for deduplication
416→  const existingObservations = await listWorkspaceOpenObservations({
417→    surreal,
418→    workspaceRecord,
419→    limit: 100,
420→  });
421→
422→  const [orphanedDecisions, staleObjectives, implsWithoutDecisions] = await Promise.all([
423→    queryOrphanedDecisions(surreal, workspaceRecord),
424→    queryStaleObjectives(surreal, workspaceRecord),
425→    queryImplementationsWithoutDecisions(surreal, workspaceRecord),
426→  ]);
427→
428→  result.orphaned_decisions_found = orphanedDecisions.length;
429→  result.stale_objectives_found = staleObjectives.length;
430→
431→  // Create observations for orphaned decisions
432→  for (const decision of orphanedDecisions) {
433→    const existingForDecision = await queryExistingObserverObservationsForEntity(
434→      surreal,
435→      workspaceRecord,
436→      decision.id as RecordId<string, string>,
437→    );
438→
439→    const observationText =
440→      `Orphaned decision: "${decision.summary}" was confirmed but has no implementing task or commit ` +
441→      `after ${COHERENCE_AGE_THRESHOLD_DAYS} days. Consider creating implementation tasks or revisiting this decision.`;
442→
443→    if (
444→      existingForDecision.length > 0 ||
445→      isAlreadyObserved(existingObservations, observationText, decision.id.id as string)
446→    ) {
447→      logInfo("observer.coherence.dedup", "Skipping duplicate orphaned decision observation", {
448→        decisionId: decision.id.id,
449→      });
450→      continue;
451→    }
452→
453→    const now = new Date();
454→    await createObservation({
455→      surreal,
456→      workspaceRecord,
457→      text: observationText,
458→      severity: "warning",
459→      sourceAgent: "observer_agent",
460→      observationType: "anomaly",
461→      now,
462→      relatedRecords: [
463→        decision.id as ObserveTargetRecord,
464→      ],
465→    });
466→    result.observations_created += 1;
467→  }
468→
469→  // Create observations for stale objectives
470→  for (const objective of staleObjectives) {
471→    const existingForObjective = await queryExistingObserverObservationsForEntity(
472→      surreal,
473→      workspaceRecord,
474→      objective.id as RecordId<string, string>,
475→    );
476→
477→    const observationText =
478→      `Stale objective: "${objective.title}" has been active for over ${COHERENCE_AGE_THRESHOLD_DAYS} days ` +
479→      `with no supporting intents. Consider aligning work to this objective or archiving it.`;
480→
481→    if (
482→      existingForObjective.length > 0 ||
483→      isAlreadyObserved(existingObservations, observationText, objective.id.id as string)
484→    ) {
485→      logInfo("observer.coherence.dedup", "Skipping duplicate stale objective observation", {
486→        objectiveId: objective.id.id,
487→      });
488→      continue;
489→    }
490→
491→    const now = new Date();
492→    await createObservation({
493→      surreal,
494→      workspaceRecord,
495→      text: observationText,
496→      severity: "warning",
497→      sourceAgent: "observer_agent",
498→      observationType: "anomaly",
499→      now,
500→      relatedRecords: [
501→        objective.id as ObserveTargetRecord,
502→      ],
503→    });
504→    result.observations_created += 1;
505→  }
506→
507→  // Create observations for implementations without decisions
508→  result.implementations_without_decisions_found = implsWithoutDecisions.length;
509→
510→  for (const task of implsWithoutDecisions) {
511→    const existingForTask = await queryExistingObserverObservationsForEntity(
512→      surreal,
513→      workspaceRecord,
514→      task.id as RecordId<string, string>,
515→    );
516→
517→    const observationText =
518→      `Implementation without decision: Task "${task.title}" was completed but has no linked decision record ` +
519→      `(no direct or feature/project-level decision link after ${COHERENCE_AGE_THRESHOLD_DAYS} days). ` +
520→      `Consider recording the decision that led to this implementation.`;
521→
522→    if (
523→      existingForTask.length > 0 ||
524→      isAlreadyObserved(existingObservations, observationText, task.id.id as string)
525→    ) {
526→      logInfo("observer.coherence.dedup", "Skipping duplicate implementation-without-decision observation", {
527→        taskId: task.id.id,
528→      });
529→      continue;
530→    }
531→
532→    const now = new Date();
533→    await createObservation({
534→      surreal,
535→      workspaceRecord,
536→      text: observationText,
537→      severity: "info",
538→      sourceAgent: "observer_agent",
539→      observationType: "validation",
540→      now,
541→      relatedRecords: [
542→        task.id as ObserveTargetRecord,
543→      ],
544→    });
545→    result.observations_created += 1;
546→  }
547→
548→  logInfo("observer.coherence.completed", "Coherence scan completed", {
549→    workspaceId: workspaceRecord.id,
550→    ...result,
551→  });
552→
553→  return result;
554→}
555→
556→// ---------------------------------------------------------------------------
557→// Scan orchestrator
558→// ---------------------------------------------------------------------------
559→
560→export async function runGraphScan(
561→  surreal: Surreal,
562→  workspaceRecord: RecordId<"workspace", string>,
563→  observerModel: LanguageModel,
564→  embeddingModel: EmbeddingModel,
565→  embeddingDimension: number,
566→  llm: GraphScanLlm = defaultLlm,
567→): Promise<GraphScanResult> {
568→  const result: GraphScanResult = {
569→    contradictions_found: 0,
570→    stale_blocked_found: 0,
571→    status_drift_found: 0,
572→    orphaned_decisions_found: 0,
573→    stale_objectives_found: 0,
574→    implementations_without_decisions_found: 0,
575→    observations_created: 0,
576→    llm_filtered_count: 0,
577→    learning_proposals_created: 0,
578→    clusters_found: 0,
579→    coverage_skips: 0,
580→    behavior_learning_proposals: 0,
581→  };
582→
583→  // Load existing observations for deduplication
584→  const existingObservations = await listWorkspaceOpenObservations({
585→    surreal,
586→    workspaceRecord,
587→    limit: 100,
588→  });
589→
590→  // 1. Detect decision-implementation contradictions (LLM-based)
591→  const [decisions, completedTasks] = await Promise.all([
592→    queryConfirmedDecisions(surreal, workspaceRecord),
593→    queryCompletedTasks(surreal, workspaceRecord),
594→  ]);
595→
596→  type ContradictionPair = { decision: ConfirmedDecision; task: CompletedTask };
597→  const contradictions: ContradictionPair[] = [];
598→
599→  if (decisions.length > 0 && completedTasks.length > 0) {
600→    const decisionMap = new Map(decisions.map((d) => [d.id.id as string, d]));
601→    const taskMap = new Map(completedTasks.map((t) => [t.id.id as string, t]));
602→
603→    const detected = await llm.detectContradictions(
604→      observerModel,
605→      decisions.map((d) => ({ id: d.id.id as string, summary: d.summary, rationale: d.rationale })),
606→      completedTasks.map((t) => ({ id: t.id.id as string, title: t.title, description: t.description })),
607→    );
608→
609→    if (detected) {
610→      for (const c of detected) {
611→        const decisionId = parseEntityRef(c.decision_ref)?.id;
612→        const taskId = parseEntityRef(c.task_ref)?.id;
613→        const decision = decisionId ? decisionMap.get(decisionId) : undefined;
614→        const task = taskId ? taskMap.get(taskId) : undefined;
615→        if (decision && task) contradictions.push({ decision, task });
616→      }
617→    }
618→  }
619→
620→  result.contradictions_found = contradictions.length;
621→
622→  // Track deduplicated entity refs so we exclude them from pattern synthesis
623→  const dedupedEntityRefs = new Set<string>();
624→
625→  for (const { decision, task } of contradictions) {
626→    // Entity-level dedup: check if observer already has an open observation on this decision
627→    const existingForDecision = await queryExistingObserverObservationsForEntity(
628→      surreal, workspaceRecord,
629→      decision.id as RecordId<string, string>,
630→    );
631→
632→    const observationText =
633→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
634→      `The task appears to implement an approach that contradicts the confirmed decision.`;
635→
636→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
637→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
638→        decisionId: decision.id.id,
639→        taskId: task.id.id,
640→      });
641→      dedupedEntityRefs.add(`decision:${decision.id.id as string}`);
642→      dedupedEntityRefs.add(`task:${task.id.id as string}`);
643→      continue;
644→    }
645→
646→    const now = new Date();
647→    await createObservation({
648→      surreal,
649→      workspaceRecord,
650→      text: observationText,
651→      severity: "conflict",
652→      sourceAgent: "observer_agent",
653→      observationType: "contradiction",
654→      now,
655→      relatedRecords: [
656→        decision.id as ObserveTargetRecord,
657→        task.id as ObserveTargetRecord,
658→      ],
659→    });
660→
661→    result.observations_created += 1;
662→  }
663→
664→  // 2. Detect stale blocked tasks and status drift (concurrent queries)
665→  const [staleBlocked, driftTasks] = await Promise.all([
666→    queryStaleBlockedTasks(surreal, workspaceRecord),
667→    queryStatusDriftTasks(surreal, workspaceRecord),
668→  ]);
669→  result.stale_blocked_found = staleBlocked.length;
670→  result.status_drift_found = driftTasks.length;
671→
672→  // 3. LLM anomaly evaluation: filter false positives before creating observations
673→  const anomalyCandidates: AnomalyCandidate[] = [];
674→
675→  for (const task of staleBlocked) {
676→    anomalyCandidates.push({
677→      entityRef: `task:${task.id.id as string}`,
678→      type: "stale_blocked",
679→      title: task.title,
680→      description: task.description,
681→      detail: `Blocked for ${task.daysBlocked} days since ${new Date(task.updated_at).toISOString().slice(0, 10)}`,
682→    });
683→  }
684→
685→  for (const drift of driftTasks) {
686→    anomalyCandidates.push({
687→      entityRef: `task:${drift.id.id as string}`,
688→      type: "status_drift",
689→      title: drift.title,
690→      description: undefined,
691→      detail: `Marked as ${drift.status} but dependency "${drift.dependency.title}" is still ${drift.dependency.status}`,
692→    });
693→  }
694→
695→  // Build evaluation map: entityRef -> LLM verdict (fallback: all relevant with default severity)
696→  const evaluationMap = new Map<string, { relevant: boolean; reasoning: string; severity: "info" | "warning" | "conflict" }>();
697→
698→  if (anomalyCandidates.length > 0) {
699→    const evaluations = await llm.evaluateAnomalies(observerModel, anomalyCandidates);
700→
701→    if (evaluations) {
702→      for (const ev of evaluations) {
703→        evaluationMap.set(ev.entity_ref, {
704→          relevant: ev.relevant,
705→          reasoning: ev.reasoning,
706→          severity: ev.suggested_severity,
707→        });
708→      }
709→    } else {
710→      logInfo("observer.llm.fallback", "Anomaly evaluation failed, treating all as relevant", {
711→        candidateCount: anomalyCandidates.length,
712→      });
713→    }
714→  }
715→
716→  // Create observations for anomalies (stale-blocked + status-drift), LLM-filtered
717→  type AnomalyObservation = {
718→    entityRef: string;
719→    taskRecord: RecordId<"task">;
720→    observationText: string;
721→    anomalyType: string;
722→    dedupContext?: Record<string, unknown>;
723→  };
724→
725→  const anomalyObservations: AnomalyObservation[] = [
726→    ...staleBlocked.map((task): AnomalyObservation => {
727→      const llmReasoning = evaluationMap.get(`task:${task.id.id as string}`)?.reasoning;
728→      return {
729→        entityRef: `task:${task.id.id as string}`,
730→        taskRecord: task.id,
731→        anomalyType: "stale-blocked",
732→        observationText: llmReasoning
733→          ? `Task blocked for ${task.daysBlocked} days: "${task.title}". ${llmReasoning}`
734→          : `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
735→            `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
736→            `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`,
737→        dedupContext: { taskId: task.id.id },
738→      };
739→    }),
740→    ...driftTasks.map((drift): AnomalyObservation => {
741→      const llmReasoning = evaluationMap.get(`task:${drift.id.id as string}`)?.reasoning;
742→      return {
743→        entityRef: `task:${drift.id.id as string}`,
744→        taskRecord: drift.id,
745→        anomalyType: "status-drift",
746→        observationText: llmReasoning
747→          ? `Status drift: Task "${drift.title}" is ${drift.status} but dependency "${drift.dependency.title}" is ${drift.dependency.status}. ${llmReasoning}`
748→          : `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
749→            `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
750→            `A task should not be completed before its dependencies.`,
751→        dedupContext: { taskId: drift.id.id, depTaskId: drift.dependency.id.id },
752→      };
753→    }),
754→  ];
755→
756→  for (const anomaly of anomalyObservations) {
757→    const evaluation = evaluationMap.get(anomaly.entityRef);
758→
759→    if (evaluation && !evaluation.relevant) {
760→      logInfo("observer.scan.llm_filtered", `${anomaly.anomalyType} task filtered by LLM as not relevant`, {
761→        taskId: (anomaly.taskRecord.id as string),
762→        reasoning: evaluation.reasoning,
763→      });
764→      result.llm_filtered_count += 1;
765→      continue;
766→    }
767→
768→    const existingForTask = await queryExistingObserverObservationsForEntity(
769→      surreal, workspaceRecord,
770→      anomaly.taskRecord as RecordId<string, string>,
771→    );
772→
773→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, anomaly.observationText, anomaly.taskRecord.id as string)) {
774→      logInfo("observer.scan.dedup", `Skipping duplicate ${anomaly.anomalyType} observation`, anomaly.dedupContext ?? {});
775→      dedupedEntityRefs.add(anomaly.entityRef);
776→      continue;
777→    }
778→
779→    const severity = evaluation?.severity ?? "warning";
780→    const now = new Date();
781→    await createObservation({
782→      surreal,
783→      workspaceRecord,
784→      text: anomaly.observationText,
785→      severity,
786→      sourceAgent: "observer_agent",
787→      observationType: "anomaly",
788→      now,
789→      relatedRecords: [anomaly.taskRecord as ObserveTargetRecord],
790→    });
791→
792→    result.observations_created += 1;
793→  }
794→
795→  // 4. LLM pattern synthesis
796→  const anomalies: Anomaly[] = [];
797→
798→  for (const { decision, task } of contradictions) {
799→    const decisionRef = `decision:${decision.id.id as string}`;
800→    const taskRef = `task:${task.id.id as string}`;
801→    if (dedupedEntityRefs.has(decisionRef) || dedupedEntityRefs.has(taskRef)) continue;
802→    anomalies.push({
803→      type: "contradiction",
804→      text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
805→      entityId: decision.id.id as string,
806→      entityTable: "decision",
807→    });
808→    anomalies.push({
809→      type: "contradiction",
810→      text: `Task "${task.title}" contradicts decision "${decision.summary}"`,
811→      entityId: task.id.id as string,
812→      entityTable: "task",
813→    });
814→  }
815→  for (const task of staleBlocked) {
816→    const entityRef = `task:${task.id.id as string}`;
817→    const evaluation = evaluationMap.get(entityRef);
818→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
819→    if (dedupedEntityRefs.has(entityRef)) continue; // skip already-observed anomalies
820→    anomalies.push({
821→      type: "stale_blocked",
822→      text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
823→      entityId: task.id.id as string,
824→      entityTable: "task",
825→    });
826→  }
827→  for (const drift of driftTasks) {
828→    const entityRef = `task:${drift.id.id as string}`;
829→    const evaluation = evaluationMap.get(entityRef);
830→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
831→    if (dedupedEntityRefs.has(entityRef)) continue; // skip already-observed anomalies
832→    anomalies.push({
833→      type: "status_drift",
834→      text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
835→      entityId: drift.id.id as string,
836→      entityTable: "task",
837→    });
838→  }
839→
840→  if (anomalies.length > 0) {
841→    const patterns = await llm.synthesizePatterns(observerModel, anomalies);
842→
843→    if (patterns) {
844→      for (const pattern of patterns) {
845→        // Dedup: check if a similar pattern observation already exists
846→        const patternText = `${pattern.pattern_name}: ${pattern.description}`;
847→        if (isAlreadyObserved(existingObservations, patternText)) {
848→          logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
849→            pattern: pattern.pattern_name,
850→          });
851→          continue;
852→        }
853→
854→        // Build related records from contributing entities
855→        const relatedRecords: ObserveTargetRecord[] = [];
856→        for (const ref of pattern.contributing_entities) {
857→          const parsed = parseEntityRef(ref);
858→          if (parsed) {
859→            relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
860→          }
861→        }
862→
863→        const now = new Date();
864→        await createObservation({
865→          surreal,
866→          workspaceRecord,
867→          text: patternText,
868→          severity: pattern.severity,
869→          sourceAgent: "observer_agent",
870→          observationType: "pattern",
871→          now,
872→          relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
873→        });
874→
875→        result.observations_created += 1;
876→      }
877→
878→      logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
879→        patternsFound: patterns.length,
880→      });
881→    } else {
882→      logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
883→        anomalyCount: anomalies.length,
884→      });
885→    }
886→  }
887→
888→  // 5. Coherence scans (deterministic, no LLM)
889→  const coherenceResult = await runCoherenceScans(surreal, workspaceRecord);
890→  result.orphaned_decisions_found = coherenceResult.orphaned_decisions_found;
891→  result.stale_objectives_found = coherenceResult.stale_objectives_found;
892→  result.implementations_without_decisions_found = coherenceResult.implementations_without_decisions_found;
893→  result.observations_created += coherenceResult.observations_created;
894→
895→  // 6. Diagnostic learning proposals: cluster observations and check coverage
896→  try {
897→    const diagnostic = await runDiagnosticClustering(surreal, workspaceRecord, observerModel, embeddingModel, embeddingDimension);
898→    result.clusters_found = diagnostic.result.clusters_found;
899→    result.coverage_skips = diagnostic.result.coverage_skips;
900→    result.learning_proposals_created = diagnostic.result.learning_proposals_created;
901→
902→    logInfo("observer.scan.diagnostic", "Diagnostic clustering completed", {
903→      workspaceId: workspaceRecord.id,
904→      clustersFound: diagnostic.result.clusters_found,
905→      coverageSkips: diagnostic.result.coverage_skips,
906→      uncoveredClusters: diagnostic.uncoveredClusters.length,
907→    });
908→  } catch (error) {
909→    logInfo("observer.scan.diagnostic_error", "Diagnostic clustering failed, continuing scan", {
910→      workspaceId: workspaceRecord.id,
911→      error: error instanceof Error ? error.message : String(error),
912→    });
913→  }
914→
915→  // 7. Behavior trend learning proposals: detect drift/flat patterns, propose learnings
916→  try {
917→    const rateLimitCheck = await checkBehaviorLearningRateLimit({
918→      surreal,
919→      workspaceRecord,
920→    });
921→
922→    if (rateLimitCheck.blocked) {
923→      logInfo("observer.scan.behavior_rate_limited", "Behavior learning proposals rate-limited", {
924→        workspaceId: workspaceRecord.id,
925→        recentProposalCount: rateLimitCheck.count,
926→      });
927→    } else {
928→      const behaviorTrends = await queryWorkspaceBehaviorTrends(surreal, workspaceRecord);
929→      const actionableTrends = behaviorTrends.filter(
930→        (t) => t.trend.pattern === "drift" || (t.trend.pattern === "flat" && t.trend.belowThreshold),
931→      );
932→
933→      for (const trend of actionableTrends) {
934→        const proposalResult = await proposeBehaviorLearning({
935→          surreal,
936→          workspaceRecord,
937→          identityId: trend.identityId,
938→          metricType: trend.metricType,
939→          behaviorIds: trend.behaviorIds,
940→          trendPattern: trend.trend.pattern,
941→          now: new Date(),
942→        });
943→
944→        if (proposalResult.created) {
945→          result.behavior_learning_proposals += 1;
946→        }
947→      }
948→
949→      logInfo("observer.scan.behavior_trends", "Behavior trend analysis completed", {
950→        workspaceId: workspaceRecord.id,
951→        totalTrends: behaviorTrends.length,
952→        actionableTrends: actionableTrends.length,
953→        proposalsCreated: result.behavior_learning_proposals,
954→      });
955→    }
956→  } catch (error) {
957→    logInfo("observer.scan.behavior_error", "Behavior trend analysis failed, continuing scan", {
958→      workspaceId: workspaceRecord.id,
959→      error: error instanceof Error ? error.message : String(error),
960→    });
961→  }
962→
963→  logInfo("observer.scan.completed", "Graph scan completed", {
964→    workspaceId: workspaceRecord.id,
965→    ...result,
966→  });
967→
968→  return result;
969→}
