  1→/**
  2→ * Intent Submission with DPoP Thumbprint Binding
  3→ *
  4→ * OAuth 2.1 RAR+DPoP intent submission endpoint.
  5→ * Validates authorization_details with type "brain_action" and dpop_jwk_thumbprint,
  6→ * creates intent record, triggers evaluation pipeline.
  7→ *
  8→ * Pure validation functions + HTTP handler factory.
  9→ */
 10→
 11→import { RecordId } from "surrealdb";
 12→import type { BrainAction } from "./types";
 13→import type { ActionSpec } from "../intent/types";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { jsonError, jsonResponse } from "../http/response";
 16→import { logError, logInfo } from "../http/observability";
 17→import { createIntent, createTrace, updateIntentStatus } from "../intent/intent-queries";
 18→import { evaluateIntent, createLlmEvaluator } from "../intent/authorizer";
 19→import { routeByRisk } from "../intent/risk-router";
 20→import {
 21→  checkIdentityAllowed,
 22→  type LookupIdentity,
 23→  type LookupManager,
 24→} from "./identity-lifecycle";
 25→
 26→// ---------------------------------------------------------------------------
 27→// Input Types
 28→// ---------------------------------------------------------------------------
 29→
 30→export type IntentSubmissionInput = {
 31→  workspace_id: string;
 32→  identity_id: string;
 33→  authorization_details: BrainAction[];
 34→  dpop_jwk_thumbprint: string;
 35→  goal: string;
 36→  reasoning: string;
 37→  priority?: number;
 38→};
 39→
 40→type ValidationResult =
 41→  | { valid: true; data: IntentSubmissionInput }
 42→  | { valid: false; error: string };
 43→
 44→// ---------------------------------------------------------------------------
 45→// Pure Validation
 46→// ---------------------------------------------------------------------------
 47→
 48→const LOW_RISK_ACTIONS = new Set(["read", "list", "get", "search", "query"]);
 49→
 50→export function validateIntentSubmission(input: unknown): ValidationResult {
 51→  if (!input || typeof input !== "object") {
 52→    return { valid: false, error: "Request body must be a non-null object" };
 53→  }
 54→
 55→  const body = input as Record<string, unknown>;
 56→
 57→  // Required string fields
 58→  const requiredStrings = ["workspace_id", "identity_id", "goal", "reasoning"] as const;
 59→  for (const field of requiredStrings) {
 60→    if (typeof body[field] !== "string" || (body[field] as string).trim().length === 0) {
 61→      return { valid: false, error: `${field} is required and must be a non-empty string` };
 62→    }
 63→  }
 64→
 65→  // dpop_jwk_thumbprint
 66→  if (typeof body.dpop_jwk_thumbprint !== "string" || (body.dpop_jwk_thumbprint as string).trim().length === 0) {
 67→    return { valid: false, error: "dpop_jwk_thumbprint is required and must be a non-empty string" };
 68→  }
 69→
 70→  // authorization_details
 71→  if (!Array.isArray(body.authorization_details)) {
 72→    return { valid: false, error: "authorization_details is required and must be an array" };
 73→  }
 74→
 75→  if (body.authorization_details.length === 0) {
 76→    return { valid: false, error: "authorization_details must contain at least one entry" };
 77→  }
 78→
 79→  for (let i = 0; i < body.authorization_details.length; i++) {
 80→    const entry = body.authorization_details[i] as Record<string, unknown>;
 81→    const validationError = validateBrainActionEntry(entry, i);
 82→    if (validationError) {
 83→      return { valid: false, error: validationError };
 84→    }
 85→  }
 86→
 87→  // Optional priority
 88→  const priority = typeof body.priority === "number" ? body.priority : undefined;
 89→
 90→  return {
 91→    valid: true,
 92→    data: {
 93→      workspace_id: (body.workspace_id as string).trim(),
 94→      identity_id: (body.identity_id as string).trim(),
 95→      authorization_details: body.authorization_details as BrainAction[],
 96→      dpop_jwk_thumbprint: (body.dpop_jwk_thumbprint as string).trim(),
 97→      goal: (body.goal as string).trim(),
 98→      reasoning: (body.reasoning as string).trim(),
 99→      ...(priority !== undefined ? { priority } : {}),
100→    },
101→  };
102→}
103→
104→export function validateBrainActionEntry(entry: Record<string, unknown>, index: number): string | undefined {
105→  if (!entry || typeof entry !== "object") {
106→    return `authorization_details[${index}] must be an object`;
107→  }
108→
109→  if (entry.type !== "brain_action") {
110→    return `authorization_details[${index}].type must be "brain_action"`;
111→  }
112→
113→  if (typeof entry.action !== "string" || entry.action.trim().length === 0) {
114→    return `authorization_details[${index}].action is required and must be a non-empty string`;
115→  }
116→
117→  if (typeof entry.resource !== "string" || entry.resource.trim().length === 0) {
118→    return `authorization_details[${index}].resource is required and must be a non-empty string`;
119→  }
120→
121→  return undefined;
122→}
123→
124→// ---------------------------------------------------------------------------
125→// Pure Transformations
126→// ---------------------------------------------------------------------------
127→
128→/** Derive backward-compatible ActionSpec from first BrainAction */
129→export function deriveActionSpec(actions: BrainAction[]): ActionSpec {
130→  const first = actions[0];
131→  return {
132→    provider: "brain",
133→    action: first.action,
134→    params: { resource: first.resource },
135→  };
136→}
137→
138→/** Check if all actions are low-risk read operations */
139→export function isLowRiskReadAction(actions: BrainAction[]): boolean {
140→  return actions.every((a) => LOW_RISK_ACTIONS.has(a.action.toLowerCase()));
141→}
142→
143→// ---------------------------------------------------------------------------
144→// HTTP Handler Factory
145→// ---------------------------------------------------------------------------
146→
147→export type IntentSubmissionDeps = {
148→  lookupIdentity: LookupIdentity;
149→  lookupManager: LookupManager;
150→};
151→
152→export function createIntentSubmissionHandler(
153→  deps: ServerDependencies,
154→  identityDeps?: IntentSubmissionDeps,
155→): (request: Request) => Promise<Response> {
156→  const { surreal } = deps;
157→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
158→
159→  // Default identity lookup from SurrealDB when no explicit ports provided
160→  const lookupIdentity: LookupIdentity = identityDeps?.lookupIdentity ?? createSurrealIdentityLookup(surreal);
161→  const lookupManager: LookupManager = identityDeps?.lookupManager ?? createSurrealManagerLookup(surreal);
162→
163→  return async (request: Request): Promise<Response> => {
164→    let body: unknown;
165→    try {
166→      body = await request.json();
167→    } catch {
168→      return jsonError("Invalid JSON body", 400);
169→    }
170→
171→    const validation = validateIntentSubmission(body);
172→    if (!validation.valid) {
173→      return jsonError(validation.error, 400);
174→    }
175→
176→    const { data } = validation;
177→    const requester = new RecordId("identity", data.identity_id);
178→    const workspace = new RecordId("workspace", data.workspace_id);
179→
180→    try {
181→      // Check identity lifecycle before creating intent
182→      const identityCheck = await checkIdentityAllowed(
183→        data.identity_id,
184→        lookupIdentity,
185→        lookupManager,
186→      );
187→
188→      if (!identityCheck.allowed) {
189→        logInfo("intent.submission.identity_blocked", "Intent submission blocked by identity check", {
190→          identityId: data.identity_id,
191→          reason: identityCheck.reason,
192→          code: identityCheck.code,
193→        });
194→        return jsonError(identityCheck.reason, 403);
195→      }
196→
197→      const actionSpec = deriveActionSpec(data.authorization_details);
198→
199→      // Create trace record for forensic call tree
200→      const traceRecord = await createTrace(surreal, {
201→        type: "intent_submission",
202→        actor: requester,
203→        workspace,
204→        input: { authorization_details: data.authorization_details, goal: data.goal },
205→      });
206→
207→      // Create intent record linked to trace
208→      const intentId = await createIntent(surreal, {
209→        goal: data.goal,
210→        reasoning: data.reasoning,
211→        priority: data.priority ?? 0,
212→        action_spec: actionSpec,
213→        trace_id: traceRecord,
214→        requester,
215→        workspace,
216→        authorization_details: data.authorization_details,
217→        dpop_jwk_thumbprint: data.dpop_jwk_thumbprint,
218→      });
219→
220→      logInfo("intent.submission.created", "Intent created via OAuth submission", {
221→        intentId: intentId.id as string,
222→        traceId: traceRecord.id as string,
223→        workspaceId: data.workspace_id,
224→      });
225→
226→      // Transition to pending_auth to trigger evaluation
227→      const transitionResult = await updateIntentStatus(
228→        surreal,
229→        intentId.id as string,
230→        "pending_auth",
231→      );
232→
233→      if (!transitionResult.ok) {
234→        logError(
235→          "intent.submission.transition_failed",
236→          "Failed to transition intent to pending_auth",
237→          new Error(transitionResult.error),
238→          { intentId: intentId.id as string },
239→        );
240→        return jsonError("Failed to submit intent for evaluation", 500);
241→      }
242→
243→      // For low-risk read actions, trigger inline evaluation for auto-approve
244→      if (isLowRiskReadAction(data.authorization_details)) {
245→        try {
246→          const evaluation = await evaluateIntent({
247→            intent: {
248→              goal: data.goal,
249→              reasoning: data.reasoning,
250→              action_spec: actionSpec,
251→            },
252→            surreal,
253→            identityId: requester,
254→            workspaceId: workspace,
255→            requesterType: "agent",
256→            llmEvaluator,
257→            timeoutMs: 10_000,
258→          });
259→
260→          const routing = routeByRisk(evaluation);
261→          const evaluationRecord = {
262→            ...evaluation,
263→            evaluated_at: new Date(),
264→          };
265→
266→          // For low-risk read actions, auto-approve unless explicitly rejected
267→          // (mirrors bridge exchange behavior: low-risk reads skip veto window)
268→          if (routing.route === "auto_approve" || (routing.route === "veto_window")) {
269→            await updateIntentStatus(surreal, intentId.id as string, "authorized", {
270→              evaluation: evaluationRecord,
271→            });
272→
273→            logInfo("intent.submission.auto_approved", "Low-risk read intent auto-approved", {
274→              intentId: intentId.id as string,
275→            });
276→
277→            return jsonResponse({
278→              intent_id: intentId.id as string,
279→              status: "authorized",
280→              trace_id: traceRecord.id as string,
281→            }, 201);
282→          }
283→        } catch (error) {
284→          logError(
285→            "intent.submission.inline_eval_failed",
286→            "Inline evaluation failed, falling back to async",
287→            error,
288→            { intentId: intentId.id as string },
289→          );
290→          // Fall through to pending_auth response
291→        }
292→      }
293→
294→      return jsonResponse({
295→        intent_id: intentId.id as string,
296→        status: "pending_auth",
297→        trace_id: traceRecord.id as string,
298→      }, 201);
299→    } catch (error) {
300→      logError("intent.submission.error", "Intent submission failed", error);
301→      return jsonError("Internal server error", 500);
302→    }
303→  };
304→}
305→
306→// ---------------------------------------------------------------------------
307→// SurrealDB Identity Lookups (adapter functions)
308→// ---------------------------------------------------------------------------
309→
310→import type { Surreal } from "surrealdb";
311→import type { ResolvedIdentity, ResolvedManager } from "./identity-lifecycle";
312→
313→type SurrealIdentityRow = {
314→  identityId: string;
315→  identityType: string;
316→  identityStatus?: string;
317→  managedBy?: string;
318→  revokedAt?: string;
319→};
320→
321→function createSurrealIdentityLookup(surreal: Surreal): LookupIdentity {
322→  return async (identityId: string) => {
323→    const rows = await surreal.query<[SurrealIdentityRow[]]>(
324→      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
325→      { identity: new RecordId("identity", identityId) },
326→    );
327→
328→    const row = rows[0]?.[0];
329→    if (!row) return undefined;
330→
331→    return {
332→      identityId: row.identityId,
333→      identityType: row.identityType as ResolvedIdentity["identityType"],
334→      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
335→      managedBy: row.managedBy,
336→      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
337→    };
338→  };
339→}
340→
341→function createSurrealManagerLookup(surreal: Surreal): LookupManager {
342→  return async (managerId: string) => {
343→    // Manager ID stored as raw string reference; look up identity by searching
344→    const rows = await surreal.query<[Array<{ identityStatus?: string }>]>(
345→      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
346→      { managerId },
347→    );
348→
349→    const row = rows[0]?.[0];
350→    if (!row) return undefined;
351→
352→    return {
353→      identityId: managerId,
354→      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
355→    };
356→  };
357→}
