  1→/**
  2→ * LLM synthesis: effect boundary for generateObject calls in pattern synthesis pipeline.
  3→ *
  4→ * Takes anomalies from deterministic graph scan and synthesizes named patterns.
  5→ * Uses AbortSignal.timeout(10_000) for latency control.
  6→ * Returns undefined on any failure.
  7→ */
  8→
  9→import { generateObject, type LanguageModel } from "ai";
 10→import { logError, logInfo } from "../http/observability";
 11→import { anomalyEvaluationResultSchema, contradictionDetectionResultSchema, synthesisResultSchema, type AnomalyEvaluation, type DetectedContradiction, type SynthesisPattern } from "./schemas";
 12→import { OBSERVER_IDENTITY } from "../agents/observer/prompt";
 13→
 14→export type Anomaly = {
 15→  type: "contradiction" | "stale_blocked" | "status_drift";
 16→  text: string;
 17→  entityId: string;
 18→  entityTable: string;
 19→};
 20→
 21→/**
 22→ * Synthesizes anomalies into named patterns via LLM.
 23→ * Returns patterns with min 2 contributing entities, or undefined on failure.
 24→ */
 25→export async function synthesizePatterns(
 26→  model: LanguageModel,
 27→  anomalies: Anomaly[],
 28→): Promise<SynthesisPattern[] | undefined> {
 29→  if (anomalies.length === 0) return [];
 30→
 31→  const start = Date.now();
 32→
 33→  // Partition large workspaces: top 20 per type
 34→  const partitioned = partitionAnomalies(anomalies, 20);
 35→
 36→  try {
 37→    const anomaliesText = partitioned.map((a) =>
 38→      `- [${a.entityTable}:${a.entityId}] (${a.type}) ${a.text}`,
 39→    ).join("\n");
 40→
 41→    const result = await generateObject({
 42→      model,
 43→      schema: synthesisResultSchema,
 44→      prompt: `You are a pattern synthesis agent analyzing workspace anomalies to identify systemic patterns.
 45→
 46→## Anomalies Detected
 47→${anomaliesText}
 48→
 49→## Instructions
 50→Analyze these anomalies and identify higher-level patterns:
 51→- "bottleneck_decision" = single decision blocking multiple tasks
 52→- "cascade_block" = chain of blocked items
 53→- "priority_drift" = priorities inconsistent with actions
 54→- "stale_cluster" = group of stale items in same area
 55→- "contradiction_cluster" = multiple contradictions sharing a root cause
 56→
 57→Rules:
 58→- Each pattern MUST reference at least 2 contributing entities using table:id format
 59→- Only include entities from the anomalies listed above
 60→- If no meaningful patterns emerge, return an empty patterns array
 61→- Set severity to "conflict" only for active contradictions`,
 62→      abortSignal: AbortSignal.timeout(10_000),
 63→    });
 64→
 65→    const latencyMs = Date.now() - start;
 66→    logInfo("observer.llm.synthesis", "LLM pattern synthesis completed", {
 67→      latencyMs,
 68→      patternCount: result.object.patterns.length,
 69→    });
 70→
 71→    // Filter patterns with < 2 contributing entities (schema enforces min 2, but defense in depth)
 72→    return result.object.patterns.filter((p) => p.contributing_entities.length >= 2);
 73→  } catch (error) {
 74→    const latencyMs = Date.now() - start;
 75→    logError("observer.llm.synthesis_error", "LLM pattern synthesis failed", {
 76→      error,
 77→      latencyMs,
 78→    });
 79→    return undefined;
 80→  }
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Contradiction detection (LLM-based)
 85→// ---------------------------------------------------------------------------
 86→
 87→export type DecisionInput = {
 88→  id: string;
 89→  summary: string;
 90→  rationale?: string;
 91→};
 92→
 93→export type TaskInput = {
 94→  id: string;
 95→  title: string;
 96→  description?: string;
 97→};
 98→
 99→/**
100→ * Detects contradictions between confirmed decisions and completed tasks via LLM.
101→ * Returns detected contradiction pairs, or undefined on failure.
102→ */
103→export async function detectContradictions(
104→  model: LanguageModel,
105→  decisions: DecisionInput[],
106→  tasks: TaskInput[],
107→): Promise<DetectedContradiction[] | undefined> {
108→  if (decisions.length === 0 || tasks.length === 0) return [];
109→
110→  const start = Date.now();
111→
112→  try {
113→    const decisionsText = decisions.map((d) =>
114→      `- [decision:${d.id}] ${d.summary}${d.rationale ? ` (rationale: ${d.rationale})` : ""}`,
115→    ).join("\n");
116→
117→    const tasksText = tasks.map((t) =>
118→      `- [task:${t.id}] ${t.title}${t.description ? ` — ${t.description}` : ""}`,
119→    ).join("\n");
120→
121→    const result = await generateObject({
122→      model,
123→      schema: contradictionDetectionResultSchema,
124→      prompt: `You are an observer agent scanning a workspace knowledge graph for contradictions between confirmed decisions and completed tasks.
125→
126→## Confirmed Decisions
127→${decisionsText}
128→
129→## Completed Tasks
130→${tasksText}
131→
132→## Instructions
133→Identify any completed task that contradicts a confirmed decision. A contradiction means the task implements an approach that directly conflicts with what the decision mandates.
134→
135→Examples of contradictions:
136→- Decision mandates tRPC but task implements REST endpoints
137→- Decision requires TypeScript but task delivers JavaScript
138→- Decision specifies PostgreSQL but task sets up MongoDB
139→- Decision requires feature flags but task ships without them
140→
141→Rules:
142→- Only flag clear, direct contradictions — not minor implementation variations
143→- Use the exact table:id format from the lists above for decision_ref and task_ref
144→- If no contradictions exist, return an empty array`,
145→      abortSignal: AbortSignal.timeout(10_000),
146→    });
147→
148→    const latencyMs = Date.now() - start;
149→    logInfo("observer.llm.contradiction_detection", "LLM contradiction detection completed", {
150→      latencyMs,
151→      contradictionCount: result.object.contradictions.length,
152→    });
153→
154→    return result.object.contradictions;
155→  } catch (error) {
156→    const latencyMs = Date.now() - start;
157→    logError("observer.llm.contradiction_detection_error", "LLM contradiction detection failed", {
158→      error,
159→      latencyMs,
160→    });
161→    return undefined;
162→  }
163→}
164→
165→// ---------------------------------------------------------------------------
166→// Anomaly evaluation (LLM-based relevance filtering for stale/drift)
167→// ---------------------------------------------------------------------------
168→
169→export type AnomalyCandidate = {
170→  entityRef: string;
171→  type: "stale_blocked" | "status_drift";
172→  title: string;
173→  description?: string;
174→  detail: string;
175→};
176→
177→/**
178→ * Evaluates stale/drift anomaly candidates via LLM to filter false positives.
179→ * Returns per-entity evaluations with relevance verdict, reasoning, and severity.
180→ * Returns undefined on failure (caller falls back to creating all observations).
181→ */
182→export async function evaluateAnomalies(
183→  model: LanguageModel,
184→  candidates: AnomalyCandidate[],
185→): Promise<AnomalyEvaluation[] | undefined> {
186→  if (candidates.length === 0) return [];
187→
188→  const start = Date.now();
189→
190→  try {
191→    const candidatesText = candidates.map((c) =>
192→      `- [${c.entityRef}] (${c.type}) "${c.title}"${c.description ? ` — ${c.description}` : ""}\n  Detail: ${c.detail}`,
193→    ).join("\n");
194→
195→    const result = await generateObject({
196→      model,
197→      system: OBSERVER_IDENTITY,
198→      schema: anomalyEvaluationResultSchema,
199→      prompt: `You are evaluating workspace anomalies to determine which ones genuinely warrant human attention and which are likely false positives.
200→
201→## Anomaly Candidates
202→${candidatesText}
203→
204→## Instructions
205→For each anomaly, evaluate whether it is genuinely concerning:
206→
207→**stale_blocked** — A task has been in "blocked" status for over 14 days.
208→- Mark as NOT relevant if the title/description suggests an expected external wait (e.g., "waiting on vendor", "pending legal review", "blocked by external API release").
209→- Mark as relevant if the task appears to be forgotten, lacks clear reason for blockage, or suggests internal coordination failure.
210→- Use "conflict" severity only when the blocked task is clearly critical or blocking other work.
211→
212→**status_drift** — A task is marked completed but has incomplete dependencies.
213→- Mark as NOT relevant if the dependency is optional, informational, or the task could reasonably be done out of order.
214→- Mark as relevant if the dependency is clearly prerequisite work that should have been done first.
215→- Use "conflict" severity when the drift could mean the completed task is actually broken.
216→
217→Return an evaluation for EVERY candidate. Use the exact entity_ref from the list above.`,
218→      abortSignal: AbortSignal.timeout(15_000),
219→    });
220→
221→    const latencyMs = Date.now() - start;
222→    const relevantCount = result.object.evaluations.filter((e) => e.relevant).length;
223→    logInfo("observer.llm.anomaly_evaluation", "LLM anomaly evaluation completed", {
224→      latencyMs,
225→      candidateCount: candidates.length,
226→      relevantCount,
227→      filteredCount: candidates.length - relevantCount,
228→    });
229→
230→    return result.object.evaluations;
231→  } catch (error) {
232→    const latencyMs = Date.now() - start;
233→    logError("observer.llm.anomaly_evaluation_error", "LLM anomaly evaluation failed", {
234→      error,
235→      latencyMs,
236→    });
237→    return undefined;
238→  }
239→}
240→
241→/**
242→ * Partitions anomalies by type and takes top N per type to manage LLM context size.
243→ */
244→function partitionAnomalies(anomalies: Anomaly[], maxPerType: number): Anomaly[] {
245→  if (anomalies.length <= maxPerType * 3) return anomalies;
246→
247→  const byType = new Map<string, Anomaly[]>();
248→  for (const a of anomalies) {
249→    const list = byType.get(a.type) ?? [];
250→    list.push(a);
251→    byType.set(a.type, list);
252→  }
253→
254→  const result: Anomaly[] = [];
255→  for (const [, list] of byType) {
256→    result.push(...list.slice(0, maxPerType));
257→  }
258→  return result;
259→}
