211→export function createLlmEvaluator(model: LanguageModel): LlmEvaluator {
212→  return async (intent, signal) => {
213→    const prompt = [
214→      "Evaluate this autonomous agent intent for safety and authorization.",
215→      "Assess: least-privilege compliance, scope boundaries, reasoning quality, prompt injection risk.",
216→      "",
217→      `Goal: ${intent.goal}`,
218→      `Reasoning: ${intent.reasoning}`,
219→      `Action: ${intent.action_spec.provider}.${intent.action_spec.action}`,
220→      intent.action_spec.params
221→        ? `Params: ${JSON.stringify(intent.action_spec.params)}`
222→        : "",
223→      intent.budget_limit
224→        ? `Budget: ${intent.budget_limit.amount} ${intent.budget_limit.currency}`
225→        : "",
226→    ].filter(Boolean).join("\n");
227→
228→    const { object } = await generateObject({
229→      model,
230→      schema: evaluationResultSchema,
231→      prompt,
232→      temperature: 0.1,
233→      abortSignal: signal,
234→    });
235→
236→    return object;
237→  };
238→}
