 19→  compareTaskCompletion,
 20→  compareIntentCompletion,
 21→  compareCommitStatus,
 22→  compareDecisionConfirmation,
 23→  compareObservationPeerReview,
 24→  shouldSkipLlm,
 25→  applyLlmVerdict,
 26→  type VerificationResult,
 27→  type IntentSignals,
 28→  type DecisionSignals,
 29→  type ObservationPeerReviewSignals,
 30→} from "../../observer/verification-pipeline";
