238→// ---------------------------------------------------------------------------
239→// Decision verification (deterministic + LLM check against completed tasks)
240→// ---------------------------------------------------------------------------
241→
242→async function verifyDecision(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
243→  const { surreal, workspaceRecord, entityId: decisionId, entityBody: body, observerModel } = input;
244→  const decisionRecord = new RecordId("decision", decisionId);
245→
246→  // Skip initial CREATE events — only verify status transitions
247→  if (!body?.updated_at) {
248→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event", { decisionId });
249→    return { observations_created: 0, verdict: "inconclusive", evidence: ["Skipped: CREATE event"] };
250→  }
251→
252→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
253→  const deterministicResult = compareDecisionConfirmation(decisionSignals);
254→
255→  await persistObservation(surreal, workspaceRecord, [decisionRecord as ObserveTargetRecord], deterministicResult);
256→  let observationsCreated = 1;
257→
258→  // LLM: when decision confirmed, check completed tasks against it (concurrent)
259→  if (observerModel && body?.status === "confirmed" && decisionSignals.completedTaskCount > 0) {
260→    const completedTasks = await queryCompletedTasks(surreal, workspaceRecord);
261→
262→    // Build contexts concurrently, then run LLM calls concurrently
263→    const taskContexts = await Promise.all(
264→      completedTasks.map(async (task) => {
265→        const taskId = task.id.id as string;
266→        const taskBody = { title: task.title, description: task.description, status: "completed" };
267→        const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, taskBody);
268→        return { task, taskId, context };
269→      }),
270→    );
271→
272→    const verdicts = await Promise.allSettled(
273→      taskContexts.map(({ context }) =>
274→        generateVerificationVerdict(observerModel, context, deterministicResult),
275→      ),
276→    );
277→
278→    for (let i = 0; i < verdicts.length; i++) {
279→      const settled = verdicts[i];
280→      if (settled.status === "rejected") {
281→        logInfo("observer.llm.error", "LLM verification failed for task", {
282→          taskId: taskContexts[i].taskId,
283→          error: String(settled.reason),
284→        });
285→        continue;
286→      }
287→
288→      const llmVerdict = settled.value;
289→      if (!llmVerdict || llmVerdict.verdict !== "mismatch") continue;
290→
291→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
292→      const taskRecord = new RecordId("task", taskContexts[i].taskId) as ObserveTargetRecord;
293→
294→      // Dedup: skip if observer already has an open observation on this task
295→      const existing = await queryExistingObserverObservationsForEntity(
296→        surreal, workspaceRecord, taskRecord as RecordId<string, string>,
297→      );
298→      if (existing.length > 0) {
299→        logInfo("observer.decision.dedup", "Skipping duplicate mismatch observation", {
300→          decisionId, taskId: taskContexts[i].taskId,
301→        });
302→        continue;
303→      }
304→
305→      await persistObservation(surreal, workspaceRecord, [decisionRecord as ObserveTargetRecord, taskRecord], finalVerdict);
306→      observationsCreated += 1;
307→    }
308→  }
309→
310→  return {
311→    observations_created: observationsCreated,
312→    verdict: deterministicResult.verdict,
313→    evidence: [deterministicResult.text],
314→  };
315→}
