317→// ---------------------------------------------------------------------------
318→// Observation peer review (deterministic + LLM)
319→// ---------------------------------------------------------------------------
320→
321→async function peerReviewObservation(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
322→  const { surreal, workspaceRecord, entityId: observationId, entityBody: body, observerModel } = input;
323→  const observationRecord = new RecordId("observation", observationId);
324→
325→  const linkedEntities = await loadObservationLinkedEntities(surreal, observationId);
326→  const peerReviewSignals = gatherPeerReviewSignals(body, linkedEntities.length);
327→  const deterministicResult = compareObservationPeerReview(peerReviewSignals);
328→
329→  // LLM peer review when model available and observation has linked entities
330→  if (observerModel) {
331→    if (linkedEntities.length > 0) {
332→      const llmVerdict = await generatePeerReviewVerdict(
333→        observerModel,
334→        peerReviewSignals.originalText,
335→        peerReviewSignals.originalSeverity,
336→        peerReviewSignals.sourceAgent,
337→        linkedEntities,
338→      );
339→
340→      if (llmVerdict) {
341→        const severity = llmVerdict.verdict === "sound" ? "info" as const
342→          : "warning" as const;
343→
344→        const reviewResult: VerificationResult = {
345→          verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
346→          severity,
347→          verified: llmVerdict.verdict === "sound",
348→          text: llmVerdict.reasoning,
349→          source: "llm",
350→          confidence: llmVerdict.confidence,
351→          observationType: "validation",
352→        };
353→
354→        await persistObservation(surreal, workspaceRecord, [observationRecord as ObserveTargetRecord], reviewResult, "llm");
355→
356→        return {
357→          observations_created: 1,
358→          verdict: reviewResult.verdict,
359→          evidence: [reviewResult.text],
360→        };
361→      }
362→
363→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
364→    } else {
365→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
366→    }
367→  }
368→
369→  // Deterministic fallback
370→  await persistObservation(surreal, workspaceRecord, [observationRecord as ObserveTargetRecord], deterministicResult, "peer_review");
371→
372→  return {
373→    observations_created: 1,
374→    verdict: deterministicResult.verdict,
375→    evidence: [deterministicResult.text],
376→  };
377→}
