544→// ---------------------------------------------------------------------------
545→// Event-driven escalation: entity observation threshold -> diagnostic pipeline
546→// ---------------------------------------------------------------------------
547→
548→const ESCALATION_THRESHOLD = 3;
549→
550→/**
551→ * Counts open observer observations linked to a specific entity.
552→ * Uses two-step approach: graph traversal then filter.
553→ */
554→async function countEntityObserverObservations(
555→  surreal: Surreal,
556→  entityTable: string,
557→  entityId: string,
558→): Promise<number> {
559→  const entityRecord = new RecordId(entityTable, entityId);
560→
561→  const [obsIds] = await surreal.query<[Array<{ obs_id: RecordId }>]>(
562→    `SELECT in AS obs_id FROM observes WHERE out = $entity;`,
563→    { entity: entityRecord },
564→  );
565→
566→  if (!obsIds || obsIds.length === 0) return 0;
567→
568→  const obsRecords = obsIds.map((r) => r.obs_id);
569→  const [countRows] = await surreal.query<[Array<{ count: number }>]>(
570→    `SELECT count() AS count FROM $records
571→     WHERE source_agent = "observer_agent"
572→       AND status = "open"
573→     GROUP ALL;`,
574→    { records: obsRecords },
575→  );
576→
577→  return countRows?.[0]?.count ?? 0;
578→}
579→
580→/**
581→ * Event-driven escalation: after persisting an observation, checks if the
582→ * entity now has 3+ open observer observations. If so, runs the diagnostic
583→ * pipeline on workspace observations (entity-scoped cluster will emerge
584→ * naturally from the clustering algorithm).
585→ *
586→ * Deduplicates against pending learnings from observer in last 24h.
587→ */
588→export async function checkAndEscalate(
589→  surreal: Surreal,
590→  workspaceRecord: RecordId<"workspace", string>,
591→  entityTable: string,
592→  entityId: string,
593→  observerModel: LanguageModel,
594→  embeddingModel: EmbeddingModel,
595→  embeddingDimension: number,
596→): Promise<void> {
597→  try {
598→    // Count observer observations for this entity
599→    const observationCount = await countEntityObserverObservations(
600→      surreal, entityTable, entityId,
601→    );
602→
603→    if (observationCount < ESCALATION_THRESHOLD) {
604→      return;
605→    }
606→
607→    logInfo("observer.escalation.threshold_met", "Entity observation threshold met, triggering diagnostic pipeline", {
608→      entityTable,
609→      entityId,
610→      observationCount,
611→    });
612→
613→    // Dedup: skip if observer already has a pending learning proposal from last 24h.
614→    // Graph scan may have already proposed a learning for this pattern.
615→    const [recentPending] = await surreal.query<[Array<{ id: RecordId }>]>(
616→      `SELECT id FROM learning
617→       WHERE workspace = $ws
618→         AND source = "agent"
619→         AND suggested_by = "observer"
620→         AND status = "pending_approval"
621→         AND created_at > time::now() - 1d
622→       LIMIT 1;`,
623→      { ws: workspaceRecord },
624→    );
625→
626→    if (recentPending && recentPending.length > 0) {
627→      logInfo("observer.escalation.dedup_skip", "Skipping escalation — pending observer learning exists from last 24h", {
628→        entityTable,
629→        entityId,
630→        pendingLearningId: recentPending[0].id.id,
631→      });
632→      return;
633→    }
634→
635→    // Run diagnostic pipeline -- clustering will naturally group
636→    // the entity's observations into a cluster
637→    await runDiagnosticClustering(
638→      surreal,
639→      workspaceRecord,
640→      observerModel,
641→      embeddingModel,
642→      embeddingDimension,
643→    );
644→
645→    logInfo("observer.escalation.completed", "Event-driven diagnostic pipeline completed", {
646→      entityTable,
647→      entityId,
648→    });
649→  } catch (error) {
650→    // Graceful failure -- escalation is best-effort, never crashes the agent
651→    logError("observer.escalation.error", "Event-driven escalation failed gracefully", {
652→      entityTable,
653→      entityId,
654→      error: error instanceof Error ? error.message : String(error),
655→    });
656→  }
657→}
