  1→/**
  2→ * Trace Response Analyzer — Observer intelligence for per-trace analysis.
  3→ *
  4→ * Pure analysis pipeline that examines LLM call traces for:
  5→ * 1. Contradictions with confirmed workspace decisions (Tier 1 KNN + Tier 2 LLM)
  6→ * 2. Unrecorded decisions (decision-shaped statements with no matching record)
  7→ *
  8→ * Pipeline: extract text -> check stop_reason -> embed response
  9→ *   -> KNN against confirmed decisions -> Tier 2 LLM verification
 10→ *   -> create observations
 11→ *
 12→ * Dependencies injected as function parameters (hexagonal ports).
 13→ * All domain logic is pure; IO happens at the boundary via injected adapters.
 14→ */
 15→
 16→import { RecordId, type Surreal } from "surrealdb";
 17→import type { LanguageModel } from "ai";
 18→import type { embed } from "ai";
 19→import { z } from "zod";
 20→import { createObservation, type ObserveTargetRecord } from "../observation/queries";
 21→import { createEmbeddingVector } from "../graph/embeddings";
 22→import { logInfo, logError } from "../http/observability";
 23→
 24→type EmbeddingModel = Parameters<typeof embed>[0]["model"];
 25→
 26→// ---------------------------------------------------------------------------
 27→// Types
 28→// ---------------------------------------------------------------------------
 29→
 30→export type TraceAnalysisInput = {
 31→  surreal: Surreal;
 32→  workspaceRecord: RecordId<"workspace", string>;
 33→  traceId: string;
 34→  traceBody?: Record<string, unknown>;
 35→  observerModel: LanguageModel;
 36→  embeddingModel: EmbeddingModel;
 37→  embeddingDimension: number;
 38→};
 39→
 40→export type TraceAnalysisResult = {
 41→  observations_created: number;
 42→  skipped: boolean;
 43→  reason?: string;
 44→};
 45→
 46→type DecisionCandidate = {
 47→  id: RecordId<"decision", string>;
 48→  summary: string;
 49→  rationale?: string;
 50→  score: number;
 51→};
 52→
 53→type ContradictionVerdict = {
 54→  isContradiction: boolean;
 55→  confidence: number;
 56→  reasoning: string;
 57→};
 58→
 59→// ---------------------------------------------------------------------------
 60→// Response text extraction (pure)
 61→// ---------------------------------------------------------------------------
 62→
 63→/**
 64→ * Extracts readable text from the trace output FLEXIBLE field.
 65→ * Handles Anthropic-style content blocks: text blocks and tool inputs.
 66→ */
 67→export function extractResponseText(output?: Record<string, unknown>): string {
 68→  if (!output) return "";
 69→
 70→  const parts: string[] = [];
 71→
 72→  // Extract from content array (Anthropic Messages API format)
 73→  const content = output.content;
 74→  if (Array.isArray(content)) {
 75→    for (const block of content) {
 76→      if (typeof block === "object" && block !== null) {
 77→        const typedBlock = block as Record<string, unknown>;
 78→        if (typedBlock.type === "text" && typeof typedBlock.text === "string") {
 79→          parts.push(typedBlock.text);
 80→        }
 81→        if (typedBlock.type === "tool_use" && typeof typedBlock.input === "object" && typedBlock.input !== null) {
 82→          // Include tool inputs as they may contain decision-shaped content
 83→          parts.push(JSON.stringify(typedBlock.input));
 84→        }
 85→      }
 86→    }
 87→  }
 88→
 89→  return parts.join("\n\n");
 90→}
 91→
 92→/**
 93→ * Checks whether a trace should be analyzed based on stop_reason.
 94→ * Tool-use stop reasons indicate intermediate loop steps -- skip them.
 95→ */
 96→export function shouldAnalyzeTrace(
 97→  stopReason?: string,
 98→  traceBody?: Record<string, unknown>,
 99→): boolean {
100→  // Check stop_reason from trace body top-level field
101→  const reason = stopReason
102→    ?? (traceBody?.stop_reason as string | undefined)
103→    ?? (traceBody?.output as Record<string, unknown> | undefined)?.stop_reason as string | undefined;
104→
105→  if (reason === "tool_use") {
106→    return false;
107→  }
108→
109→  return true;
110→}
111→
112→// ---------------------------------------------------------------------------
113→// KNN decision search (two-step SurrealDB v3.0 workaround)
114→// ---------------------------------------------------------------------------
115→
116→/**
117→ * Finds confirmed decisions similar to the given embedding using two-step
118→ * KNN query pattern (SurrealDB v3.0 workaround for KNN + WHERE bug).
119→ *
120→ * Step 1: KNN on HNSW index (no WHERE filter)
121→ * Step 2: Filter by workspace + confirmed status (B-tree index)
122→ */
123→async function findSimilarDecisions(
124→  surreal: Surreal,
125→  workspaceRecord: RecordId<"workspace", string>,
126→  responseEmbedding: number[],
127→  threshold: number,
128→): Promise<DecisionCandidate[]> {
129→  const results = await surreal.query(
130→    `LET $candidates = SELECT id, summary, rationale, workspace, status,
131→        vector::similarity::cosine(embedding, $vec) AS score
132→      FROM decision WHERE embedding <|20, COSINE|> $vec;
133→     SELECT id, summary, rationale, score FROM $candidates
134→      WHERE workspace = $ws AND status = 'confirmed'
135→        AND score >= $threshold
136→      ORDER BY score DESC
137→      LIMIT 10;`,
138→    { vec: responseEmbedding, ws: workspaceRecord, threshold },
139→  );
140→
141→  // Two-statement query: results[1] is the filtered result
142→  const rows = (results[1] ?? []) as Array<{
143→    id: RecordId<"decision", string>;
144→    summary: string;
145→    rationale?: string;
146→    score: number;
147→  }>;
148→
149→  return rows;
150→}
151→
152→// ---------------------------------------------------------------------------
153→// Tier 2 LLM verification
154→// ---------------------------------------------------------------------------
155→
156→/**
157→ * Verifies whether a trace response actually contradicts a specific decision.
158→ * Returns structured verdict with confidence score.
159→ */
160→async function verifyContradiction(
161→  model: LanguageModel,
162→  responseText: string,
163→  decision: DecisionCandidate,
164→): Promise<ContradictionVerdict> {
165→  const { generateObject } = await import("ai");
166→
167→  const contradictionSchema = z.object({
168→    is_contradiction: z.boolean().describe("Whether the response contradicts the decision"),
169→    confidence: z.number().describe("Confidence score 0.0-1.0"),
170→    reasoning: z.string().describe("Brief explanation"),
171→  });
172→
173→  const { object } = await generateObject({
174→    model,
175→    schema: contradictionSchema,
176→    prompt: `You are an AI governance observer. Determine if this LLM response contradicts a confirmed workspace decision.
177→
178→CONFIRMED DECISION:
179→Summary: ${decision.summary}
180→${decision.rationale ? `Rationale: ${decision.rationale}` : ""}
181→
182→LLM RESPONSE EXCERPT:
183→${responseText.slice(0, 2000)}
184→
185→Does the LLM response implement or recommend something that directly contradicts this decision? Consider:
186→- Is the response actively violating the decision (not just mentioning alternatives)?
187→- Is the contradiction about the same domain/scope as the decision?
188→- Could the response be about external/third-party systems (not covered by the decision)?
189→
190→Respond with is_contradiction (true/false), confidence (0.0-1.0), and brief reasoning.`,
191→  });
192→
193→  return {
194→    isContradiction: object.is_contradiction,
195→    confidence: object.confidence,
196→    reasoning: object.reasoning,
197→  };
198→}
199→
200→/**
201→ * Verifies whether a trace response contains an unrecorded decision.
202→ * Checks if the text makes architectural/strategic choices not in the graph.
203→ */
204→async function verifyMissingDecision(
205→  model: LanguageModel,
206→  responseText: string,
207→): Promise<{ isDecision: boolean; confidence: number; summary: string }> {
208→  const { generateObject } = await import("ai");
209→
210→  const missingDecisionSchema = z.object({
211→    is_decision: z.boolean().describe("Whether the response contains an unrecorded architectural/strategic decision"),
212→    confidence: z.number().describe("Confidence score 0.0-1.0"),
213→    summary: z.string().describe("Brief summary of the decision found, or empty string"),
214→  });
215→
216→  const { object } = await generateObject({
217→    model,
218→    schema: missingDecisionSchema,
219→    prompt: `You are an AI governance observer. Determine if this LLM response contains an architectural or strategic decision that should be tracked.
220→
221→LLM RESPONSE:
222→${responseText.slice(0, 2000)}
223→
224→Decision signals to look for:
225→- "I've decided to use X instead of Y"
226→- "The right approach is X because..."
227→- Technology/framework/architecture choices with rationale
228→- Trade-off resolutions ("we should use X for this use case")
229→
230→NOT decisions:
231→- Implementation details (variable names, code formatting)
232→- Following existing instructions/conventions
233→- Asking questions or presenting options without choosing
234→
235→Does this response contain a decision-shaped statement? Respond with is_decision, confidence (0.0-1.0), and a summary of the decision if found.`,
236→  });
237→
238→  return {
239→    isDecision: object.is_decision,
240→    confidence: object.confidence,
241→    summary: object.summary,
242→  };
243→}
