245→// ---------------------------------------------------------------------------
246→// Contradiction detection pipeline
247→// ---------------------------------------------------------------------------
248→
249→async function detectContradictions(
250→  input: TraceAnalysisInput,
251→  responseText: string,
252→  responseEmbedding: number[],
253→  config: { tier1Threshold: number; tier2ConfidenceMin: number },
254→): Promise<number> {
255→  const { surreal, workspaceRecord, traceId, observerModel } = input;
256→  const traceRecord = new RecordId("trace", traceId);
257→
258→  // Tier 1: KNN search for similar confirmed decisions
259→  const candidates = await findSimilarDecisions(
260→    surreal,
261→    workspaceRecord,
262→    responseEmbedding,
263→    config.tier1Threshold,
264→  );
265→
266→  if (candidates.length === 0) {
267→    logInfo("observer.trace.no_candidates", "No similar decisions found for trace", { traceId });
268→    return 0;
269→  }
270→
271→  logInfo("observer.trace.candidates_found", "KNN candidates for contradiction check", {
272→    traceId,
273→    candidateCount: candidates.length,
274→  });
275→
276→  // Tier 2: LLM verification on each candidate
277→  let observationsCreated = 0;
278→
279→  for (const candidate of candidates) {
280→    try {
281→      const verdict = await verifyContradiction(observerModel, responseText, candidate);
282→
283→      if (!verdict.isContradiction || verdict.confidence < config.tier2ConfidenceMin) {
284→        logInfo("observer.trace.not_contradicted", "Candidate not contradicted or low confidence", {
285→          traceId,
286→          decisionId: candidate.id.id,
287→          isContradiction: verdict.isContradiction,
288→          confidence: verdict.confidence,
289→        });
290→        continue;
291→      }
292→
293→      // Create contradiction observation
294→      const decisionRecord = new RecordId("decision", candidate.id.id as string) as ObserveTargetRecord;
295→
296→      await createObservation({
297→        surreal,
298→        workspaceRecord,
299→        text: `Trace response contradicts confirmed decision "${candidate.summary}": ${verdict.reasoning}`,
300→        severity: "conflict",
301→        sourceAgent: "observer_agent",
302→        observationType: "contradiction",
303→        now: new Date(),
304→        relatedRecords: [traceRecord as ObserveTargetRecord, decisionRecord],
305→        confidence: verdict.confidence,
306→        verified: true,
307→        source: "llm",
308→      });
309→
310→      observationsCreated += 1;
311→
312→      logInfo("observer.trace.contradiction_found", "Contradiction observation created", {
313→        traceId,
314→        decisionId: candidate.id.id,
315→        confidence: verdict.confidence,
316→      });
317→    } catch (error) {
318→      logError("observer.trace.verification_error", "Tier 2 verification failed for candidate", {
319→        traceId,
320→        decisionId: candidate.id.id,
321→        error: error instanceof Error ? error.message : String(error),
322→      });
323→      // Continue with other candidates -- fail-skip per candidate
324→    }
325→  }
326→
327→  return observationsCreated;
328→}
329→
330→// ---------------------------------------------------------------------------
331→// Missing decision detection pipeline
332→// ---------------------------------------------------------------------------
333→
334→async function detectMissingDecisions(
335→  input: TraceAnalysisInput,
336→  responseText: string,
337→  responseEmbedding: number[],
338→  config: { tier1Threshold: number; tier2ConfidenceMin: number },
339→): Promise<number> {
340→  const { surreal, workspaceRecord, traceId, observerModel } = input;
341→  const traceRecord = new RecordId("trace", traceId);
342→
343→  // First check if the response contains decision signals via LLM
344→  try {
345→    const missingResult = await verifyMissingDecision(observerModel, responseText);
346→
347→    if (!missingResult.isDecision || missingResult.confidence < config.tier2ConfidenceMin) {
348→      return 0;
349→    }
350→
351→    // Check if a similar decision already exists (KNN search)
352→    const existingDecisions = await findSimilarDecisions(
353→      surreal,
354→      workspaceRecord,
355→      responseEmbedding,
356→      config.tier1Threshold,
357→    );
358→
359→    // If we found a similar existing decision, it's not "missing"
360→    if (existingDecisions.length > 0) {
361→      logInfo("observer.trace.decision_exists", "Decision-shaped content matches existing decision", {
362→        traceId,
363→        matchedDecisionId: existingDecisions[0].id.id,
364→      });
365→      return 0;
366→    }
367→
368→    // No matching decision found -- create info observation
369→    await createObservation({
370→      surreal,
371→      workspaceRecord,
372→      text: `Unrecorded decision detected in trace: ${missingResult.summary}`,
373→      severity: "info",
374→      sourceAgent: "observer_agent",
375→      observationType: "validation",
376→      now: new Date(),
377→      relatedRecords: [traceRecord as ObserveTargetRecord],
378→      confidence: missingResult.confidence,
379→      verified: true,
380→      source: "llm",
381→    });
382→
383→    logInfo("observer.trace.missing_decision", "Unrecorded decision observation created", {
384→      traceId,
385→      summary: missingResult.summary,
386→    });
387→
388→    return 1;
389→  } catch (error) {
390→    logError("observer.trace.missing_detection_error", "Missing decision detection failed", {
391→      traceId,
392→      error: error instanceof Error ? error.message : String(error),
393→    });
394→    return 0;
395→  }
396→}
