402→async function loadIntelligenceConfig(
403→  surreal: Surreal,
404→  workspaceRecord: RecordId<"workspace", string>,
405→): Promise<{
406→  enabled: boolean;
407→  tier1Threshold: number;
408→  tier2ConfidenceMin: number;
409→} | undefined> {
410→  const [rows] = await surreal.query<[Array<{
411→    contradiction_detection_enabled: boolean;
412→    contradiction_tier1_threshold: number;
413→    contradiction_tier2_confidence_min: number;
414→  }>]>(
415→    `SELECT contradiction_detection_enabled, contradiction_tier1_threshold, contradiction_tier2_confidence_min
416→     FROM proxy_intelligence_config
417→     WHERE workspace = $ws
418→     LIMIT 1;`,
419→    { ws: workspaceRecord },
420→  );
421→
422→  const config = rows?.[0];
423→  if (!config) return undefined;
424→
425→  return {
426→    enabled: config.contradiction_detection_enabled,
427→    tier1Threshold: config.contradiction_tier1_threshold,
428→    tier2ConfidenceMin: config.contradiction_tier2_confidence_min,
429→  };
430→}
