433→// Main analysis entry point
434→// ---------------------------------------------------------------------------
435→
436→/**
437→ * Analyzes an LLM call trace for contradictions and missing decisions.
438→ *
439→ * Pipeline:
440→ * 1. Check stop_reason -- skip tool_use (intermediate loop step)
441→ * 2. Extract text blocks from output FLEXIBLE field
442→ * 3. Contradiction detection: embed response -> KNN against decisions -> LLM verify
443→ * 4. Missing decision detection: extract signals -> embed -> KNN -> LLM verify
444→ *
445→ * Returns 200-safe result on all analysis errors (fail-skip pattern).
446→ */
447→export async function analyzeTraceResponse(
448→  input: TraceAnalysisInput,
449→): Promise<TraceAnalysisResult> {
450→  const { surreal, workspaceRecord, traceId, traceBody, embeddingModel, embeddingDimension } = input;
451→
452→  // Step 1: Check stop_reason
453→  if (!shouldAnalyzeTrace(undefined, traceBody)) {
454→    logInfo("observer.trace.skipped", "Trace skipped: tool_use stop_reason", { traceId });
455→    return { observations_created: 0, skipped: true, reason: "tool_use" };
456→  }
457→
458→  // Step 2: Extract response text
459→  const output = traceBody?.output as Record<string, unknown> | undefined;
460→  const responseText = extractResponseText(output);
461→
462→  if (responseText.trim().length === 0) {
463→    logInfo("observer.trace.empty", "Trace skipped: no extractable text", { traceId });
464→    return { observations_created: 0, skipped: true, reason: "empty_response" };
465→  }
466→
467→  // Load intelligence config
468→  const config = await loadIntelligenceConfig(surreal, workspaceRecord);
469→  if (!config || !config.enabled) {
470→    logInfo("observer.trace.config_disabled", "Trace analysis skipped: not enabled", { traceId });
471→    return { observations_created: 0, skipped: true, reason: "not_enabled" };
472→  }
473→
474→  // Step 3: Embed the response text
475→  const responseEmbedding = await createEmbeddingVector(
476→    embeddingModel,
477→    responseText.slice(0, 4000), // Limit embedding input
478→    embeddingDimension,
479→  );
480→
481→  if (!responseEmbedding) {
482→    logError("observer.trace.embedding_failed", "Failed to embed trace response", { traceId });
483→    return { observations_created: 0, skipped: true, reason: "embedding_failed" };
484→  }
485→
486→  // Step 4: Run both detection pipelines
487→  const [contradictionCount, missingCount] = await Promise.all([
488→    detectContradictions(input, responseText, responseEmbedding, config),
489→    detectMissingDecisions(input, responseText, responseEmbedding, config),
490→  ]);
491→
492→  const totalObservations = contradictionCount + missingCount;
493→
494→  logInfo("observer.trace.analysis_complete", "Trace analysis complete", {
495→    traceId,
496→    contradictions: contradictionCount,
497→    missingDecisions: missingCount,
498→    totalObservations,
499→  });
500→
501→  return {
502→    observations_created: totalObservations,
503→    skipped: false,
504→  };
505→}
