 65→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 66→  const { entityTable } = input;
 67→
 68→  let result: ObserverAgentOutput;
 69→
 70→  switch (entityTable) {
 71→    case "task":
 72→      result = await verifyTask(input);
 73→      break;
 74→    case "intent":
 75→      result = await verifyIntent(input);
 76→      break;
 77→    case "git_commit":
 78→      result = await verifyCommit(input);
 79→      break;
 80→    case "decision":
 81→      result = await verifyDecision(input);
 82→      break;
 83→    case "observation":
 84→      result = await peerReviewObservation(input);
 85→      break;
 86→    case "trace":
 87→      // Trace analysis is handled by the trace-response-analyzer at the route level.
 88→      // This case exists for completeness; the route dispatches directly.
 89→      return {
 90→        observations_created: 0,
 91→        verdict: "inconclusive",
 92→        evidence: ["Trace analysis handled by trace-response-analyzer at route level"],
 93→      };
 94→    case "agent_session":
 95→      // Session-end analysis is handled by the session-trace-analyzer at the route level.
 96→      // This case exists for completeness; the route dispatches directly.
 97→      return {
 98→        observations_created: 0,
 99→        verdict: "inconclusive",
100→        evidence: ["Session analysis handled by session-trace-analyzer at route level"],
101→      };
102→    default:
103→      return {
104→        observations_created: 0,
105→        verdict: "inconclusive",
106→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
107→      };
108→  }
109→
110→  // Event-driven escalation: check if this entity now has enough
111→  // observations to trigger the diagnostic learning pipeline.
112→  // Skip for observation peer reviews (avoid recursive escalation).
113→  if (result.observations_created > 0 && entityTable !== "observation"
114→    && input.observerModel && input.embeddingModel && input.embeddingDimension) {
115→    await checkAndEscalate(
116→      input.surreal,
117→      input.workspaceRecord,
118→      input.entityTable,
119→      input.entityId,
120→      input.observerModel,
121→      input.embeddingModel,
122→      input.embeddingDimension,
123→    );
124→  }
125→
126→  return result;
127→}
