133→async function verifyTask(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
134→  const { surreal, workspaceRecord, entityId: taskId, entityBody: body, observerModel } = input;
135→  const taskRecord = new RecordId("task", taskId);
136→  const evidence: string[] = [];
137→
138→  // Deterministic: gather external signals (commits, CI)
139→  const signalsResult = await gatherTaskSignals(surreal, taskId);
140→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
141→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
142→
143→  const deterministicResult = compareTaskCompletion(signalsResult);
144→  evidence.push(`Verdict: ${deterministicResult.verdict}`);
145→  evidence.push(deterministicResult.text);
146→
147→  // LLM reasoning path
148→  if (observerModel) {
149→    const skipDeterministic = await loadWorkspaceSkipSetting(surreal, workspaceRecord);
150→
151→    if (shouldSkipLlm(deterministicResult, skipDeterministic)) {
152→      logInfo("observer.llm.skip", "LLM skipped: deterministic match + CI passing", { taskId });
153→    } else {
154→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, body);
155→
156→      // Only invoke LLM when there are decisions to check against.
157→      // Without decisions, semantic verification has nothing to compare --
158→      // the deterministic CI-based verdict should stand.
159→      if (context.relatedDecisions.length === 0) {
160→        logInfo("observer.llm.skip", "LLM skipped: no related decisions to verify against", { taskId });
161→        await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
162→        return {
163→          observations_created: 1,
164→          verdict: deterministicResult.verdict,
165→          evidence,
166→        };
167→      }
168→
169→      const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
170→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
171→
172→      // Link contradicted decisions via observes edges
173→      const additionalRecords = extractDecisionRecords(llmVerdict?.evidence_refs);
174→
175→      await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord, ...additionalRecords], finalVerdict);
176→
177→      return {
178→        observations_created: 1,
179→        verdict: finalVerdict.verdict,
180→        evidence,
181→      };
182→    }
183→  }
184→
185→  // Deterministic-only path
186→  await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
187→
188→  return {
189→    observations_created: 1,
190→    verdict: deterministicResult.verdict,
191→    evidence,
192→  };
193→}
