 80→const DEFAULT_EVAL_TIMEOUT_MS = 30_000;
 81→
 82→export async function evaluateIntent(
 83→  input: EvaluateIntentInput,
 84→): Promise<EvaluationOutput> {
 85→  const intentContext: IntentEvaluationContext = {
 86→    goal: input.intent.goal,
 87→    reasoning: input.intent.reasoning,
 88→    priority: input.intent.priority ?? 0,
 89→    action_spec: input.intent.action_spec,
 90→    budget_limit: input.intent.budget_limit,
 91→    requester_type: input.requesterType,
 92→    requester_role: input.requesterRole,
 93→  };
 94→
 95→  const gateResult = await evaluatePolicyGate(
 96→    input.surreal,
 97→    input.identityId,
 98→    input.workspaceId,
 99→    intentContext,
100→  );
101→
102→  if (!gateResult.passed) {
103→    return {
104→      decision: "REJECT",
105→      risk_score: 0,
106→      reason: gateResult.reason,
107→      policy_only: true,
108→      policy_trace: gateResult.policy_trace,
109→      human_veto_required: false,
110→    };
111→  }
112→
113→  const humanVetoRequired = gateResult.human_veto_required;
114→  const policyTrace = gateResult.policy_trace;
115→
116→  const timeoutMs = input.timeoutMs ?? DEFAULT_EVAL_TIMEOUT_MS;
117→  const controller = new AbortController();
118→  const timer = setTimeout(() => controller.abort(), timeoutMs);
119→
120→  // --- Alignment step (warning mode: never blocks authorization) ---
121→  // Runs inside the timeout block so KNN + edge writes share the abort budget.
122→  let alignmentResult: AlignmentResult | undefined;
123→  if (input.intentEmbedding && input.findAlignedObjectives) {
124→    try {
125→      const candidates = await input.findAlignedObjectives(
126→        input.intentEmbedding,
127→        input.workspaceId,
128→      );
129→      alignmentResult = selectBestAlignment(candidates);
130→
131→      // Create supports edge if matched and ports are available
132→      if (
133→        alignmentResult.classification === "matched" &&
134→        alignmentResult.objectiveId &&
135→        input.intentId &&
136→        input.createSupportsEdge
137→      ) {
138→        await input.createSupportsEdge(
139→          input.intentId,
140→          alignmentResult.objectiveId,
141→          alignmentResult.score,
142→          "embedding",
143→        );
144→      }
145→
146→      // Create warning observation when no objective matches (warning mode)
147→      if (
148→        alignmentResult.classification === "none" &&
149→        candidates.length > 0 &&
150→        input.intentId &&
151→        input.createAlignmentWarning
152→      ) {
153→        await input.createAlignmentWarning(
154→          input.workspaceId,
155→          input.intentId,
156→          alignmentResult.score,
157→        );
158→      }
159→    } catch (error) {
160→      if (isAbortError(error)) throw error;
161→      // Non-timeout alignment failure never blocks intent authorization
162→      alignmentResult = { classification: "none", score: 0 };
163→    }
164→  }
165→
166→  try {
167→    const llmResult = await input.llmEvaluator(input.intent, controller.signal);
168→    return {
169→      ...llmResult,
170→      policy_only: false,
171→      policy_trace: policyTrace,
172→      human_veto_required: humanVetoRequired,
173→      alignment: alignmentResult,
174→    };
175→  } catch (error) {
176→    const reason = isAbortError(error)
177→      ? "LLM evaluation timeout — falling back to policy-only with veto window"
178→      : `LLM evaluation failed: ${error instanceof Error ? error.message : String(error)} — falling back to policy-only with veto window`;
179→    return {
180→      decision: "APPROVE",
181→      risk_score: 50,
182→      reason,
183→      policy_only: true,
184→      policy_trace: policyTrace,
185→      human_veto_required: humanVetoRequired,
186→      alignment: alignmentResult,
187→    };
188→  } finally {
189→    clearTimeout(timer);
190→  }
191→}
192→
193→function isAbortError(error: unknown): boolean {
194→  return error instanceof DOMException && error.name === "AbortError";
195→}
