248→// ---------------------------------------------------------------------------
249→// SSE Helpers
250→// ---------------------------------------------------------------------------
251→
252→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
253→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
254→  if (!response.ok || !response.body) {
255→    throw new Error(`Failed to open SSE stream (${response.status})`);
256→  }
257→
258→  const reader = response.body.getReader();
259→  const decoder = new TextDecoder();
260→  const events: T[] = [];
261→  let buffer = "";
262→
263→  const timeout = setTimeout(() => {
264→    void reader.cancel();
265→  }, timeoutMs);
266→
267→  try {
268→    while (true) {
269→      const { value, done } = await reader.read();
270→      if (done) {
271→        break;
272→      }
273→
274→      buffer += decoder.decode(value, { stream: true });
275→      const segments = buffer.split("\n\n");
276→      buffer = segments.pop() ?? "";
277→
278→      for (const segment of segments) {
279→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
280→        if (!dataLine) {
281→          continue;
282→        }
283→
284→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
285→        events.push(event);
286→
287→        if (event.type === "error") {
288→          const errorText = (event as { error?: string }).error;
289→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
290→        }
291→
292→        if (event.type === "done") {
293→          return events;
294→        }
295→      }
296→    }
297→  } finally {
298→    clearTimeout(timeout);
299→    reader.releaseLock();
300→  }
301→
302→  return events;
303→}
