327→function base64url(buf: Buffer): string {
328→  return buf.toString("base64url");
329→}
330→
331→function generatePkce(): { verifier: string; challenge: string } {
332→  const verifier = base64url(randomBytes(32));
333→  const challenge = base64url(createHash("sha256").update(verifier).digest());
334→  return { verifier, challenge };
