337→/**
338→ * Obtain an OAuth2 JWT access token for MCP endpoints.
339→ * Requires a SurrealDB connection to skip consent screen.
340→ */
341→export async function getOAuthToken(
342→  baseUrl: string,
343→  surreal: Surreal,
344→  sessionHeaders: Record<string, string>,
345→  scopes: string = "graph:read graph:reason session:write offline_access",
346→): Promise<string> {
347→  // Trigger JWKS key generation if not yet done
348→  await fetch(`${baseUrl}/api/auth/jwks`);
349→
350→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
351→    method: "POST",
352→    headers: { "Content-Type": "application/json" },
353→    body: JSON.stringify({
354→      client_name: `test-client-${Date.now()}`,
355→      redirect_uris: ["http://127.0.0.1:9999/callback"],
356→      grant_types: ["authorization_code", "refresh_token"],
357→      response_types: ["code"],
358→      token_endpoint_auth_method: "none",
359→    }),
360→  });
361→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
362→
363→  const { client_id } = (await dcrRes.json()) as { client_id: string };
364→
365→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
366→    cid: client_id,
367→  });
368→
369→  const { verifier, challenge } = generatePkce();
370→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
371→  authUrl.searchParams.set("client_id", client_id);
372→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
373→  authUrl.searchParams.set("response_type", "code");
374→  authUrl.searchParams.set("scope", scopes);
375→  authUrl.searchParams.set("state", "test-state");
376→  authUrl.searchParams.set("code_challenge", challenge);
377→  authUrl.searchParams.set("code_challenge_method", "S256");
378→  authUrl.searchParams.set("resource", baseUrl);
379→
380→  const authRes = await fetch(authUrl.toString(), {
381→    headers: sessionHeaders,
382→    redirect: "manual",
383→  });
384→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
385→
386→  const location = authRes.headers.get("location")!;
387→  const redirectUrl = new URL(location, baseUrl);
388→  const code = redirectUrl.searchParams.get("code") ?? "";
389→  if (!code) throw new Error(`No code in redirect: ${location}`);
390→
391→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
392→    method: "POST",
393→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
394→    body: new URLSearchParams({
395→      grant_type: "authorization_code",
396→      code,
397→      redirect_uri: "http://127.0.0.1:9999/callback",
398→      client_id,
399→      code_verifier: verifier,
400→      resource: baseUrl,
401→    }),
402→  });
403→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
404→
405→  const tokens = (await tokenRes.json()) as { access_token: string };
406→  return tokens.access_token;
407→}
