555→      intent_id: intentId,
556→      authorization_details: broadActions,
557→    }),
558→  });
559→
560→  if (!tokenRes.ok) {
561→    const body = await tokenRes.text();
562→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
563→  }
564→
565→  const { access_token } = (await tokenRes.json()) as { access_token: string };
566→
567→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
568→    const method = options?.method ?? "POST";
569→    const requestUri = `${baseUrl}${path}`;
570→    const proof = await createDPoPProof(keyPair, method, requestUri);
571→
572→    return fetch(requestUri, {
573→      method,
574→      headers: {
575→        "Content-Type": "application/json",
576→        Authorization: `DPoP ${access_token}`,
577→        DPoP: proof,
578→      },
579→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
580→    });
581→  };
582→
583→  return {
584→    ...user,
585→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
586→    mcpFetch,
587→    accessToken: access_token,
588→    keyPair,
589→    workspaceId,
590→    identityId,
591→  };
592→}
593→
594→// ---------------------------------------------------------------------------
595→// DPoP Helpers
596→// ---------------------------------------------------------------------------
597→
598→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
599→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
600→    { name: "ECDSA", namedCurve: "P-256" },
601→    true,
602→    ["sign", "verify"],
603→  );
604→
605→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
606→  const thumbprint = await computeDPoPThumbprint(publicJwk);
607→
608→  return { privateKey, publicKey, publicJwk, thumbprint };
609→}
610→
611→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
612→  const thumbprintInput = JSON.stringify({
613→    crv: publicJwk.crv,
614→    kty: publicJwk.kty,
615→    x: publicJwk.x,
616→    y: publicJwk.y,
617→  });
618→
619→  const hashBuffer = await crypto.subtle.digest(
620→    "SHA-256",
621→    new TextEncoder().encode(thumbprintInput),
622→  );
623→
624→  return base64urlBytes(new Uint8Array(hashBuffer));
625→}
626→
627→async function createDPoPProof(
628→  keyPair: DPoPKeyPair,
629→  method: string,
630→  targetUri: string,
631→): Promise<string> {
632→  const header = {
633→    typ: "dpop+jwt" as const,
634→    alg: "ES256" as const,
635→    jwk: {
636→      kty: keyPair.publicJwk.kty,
637→      crv: keyPair.publicJwk.crv,
638→      x: keyPair.publicJwk.x,
639→      y: keyPair.publicJwk.y,
640→    },
641→  };
642→
643→  const payload = {
644→    jti: crypto.randomUUID(),
645→    htm: method,
646→    htu: targetUri,
647→    iat: Math.floor(Date.now() / 1000),
648→  };
649→
650→  const importedKey = await jose.importJWK(
651→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
652→    "ES256",
653→  );
654→
655→  return await new jose.SignJWT(payload)
656→    .setProtectedHeader(header)
657→    .sign(importedKey);
658→}
659→
660→function base64urlBytes(bytes: Uint8Array): string {
661→  const binary = String.fromCharCode(...bytes);
662→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
663→}
