677→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
678→  return await Promise.race([
679→    callback(),
680→    new Promise<T>((_, reject) => {
681→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
682→    }),
683→  ]);
684→}
