 67→export async function acknowledgeObservation(input: {
 68→  surreal: Surreal;
 69→  workspaceRecord: RecordId<"workspace", string>;
 70→  observationRecord: ObservationRecord;
 71→  now: Date;
 72→}): Promise<void> {
 73→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 74→  if (!row) {
 75→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 76→  }
 77→
 78→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 79→    throw new Error("observation is outside the current workspace scope");
 80→  }
 81→
 82→  await input.surreal.update(input.observationRecord).merge({
 83→    status: "acknowledged" satisfies ObservationStatus,
 84→    updated_at: input.now,
 85→  });
 86→}
 87→
 88→export async function resolveObservation(input: {
 89→  surreal: Surreal;
 90→  workspaceRecord: RecordId<"workspace", string>;
 91→  observationRecord: ObservationRecord;
 92→  now: Date;
 93→  resolvedByRecord?: RecordId<"identity", string>;
 94→}): Promise<void> {
 95→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 96→  if (!row) {
 97→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 98→  }
 99→
100→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
101→    throw new Error("observation is outside the current workspace scope");
102→  }
103→
104→  await input.surreal.update(input.observationRecord).merge({
105→    status: "resolved" satisfies ObservationStatus,
106→    resolved_at: input.now,
107→    ...(input.resolvedByRecord ? { resolved_by: input.resolvedByRecord } : {}),
108→    updated_at: input.now,
109→  });
110→}
111→
112→type OpenObservationRow = {
113→  id: ObservationRecord;
114→  text: string;
115→  severity: ObservationSeverity;
116→  status: ObservationStatus;
117→  category?: EntityCategory;
118→  source_agent: string;
119→  created_at: string | Date;
120→};
121→
122→export async function listWorkspaceOpenObservations(input: {
123→  surreal: Surreal;
124→  workspaceRecord: RecordId<"workspace", string>;
125→  limit: number;
126→}): Promise<ObservationSummary[]> {
127→  const [rows] = await input.surreal
128→    .query<[OpenObservationRow[]]>(
129→      [
130→        "SELECT id, text, severity, status, category, source_agent, created_at",
131→        "FROM observation",
132→        "WHERE workspace = $workspace",
133→        "AND status IN ['open', 'acknowledged']",
134→        "ORDER BY created_at DESC",
135→        "LIMIT $limit;",
136→      ].join(" "),
137→      {
138→        workspace: input.workspaceRecord,
139→        limit: input.limit,
140→      },
141→    )
142→    .collect<[OpenObservationRow[]]>();
143→
144→  return rows
145→    .slice()
146→    .sort((a, b) => {
147→      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
148→      if (severityDelta !== 0) {
149→        return severityDelta;
150→      }
151→
152→      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
153→    })
154→    .map((row) => ({
155→      id: row.id.id as string,
156→      text: row.text,
157→      severity: row.severity,
158→      status: row.status,
159→      ...(row.category ? { category: row.category } : {}),
160→      sourceAgent: row.source_agent,
161→      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
162→    }));
163→}
