222→/**
223→ * Creates a task linked to a source commit in the graph.
224→ * Used as a Given-step precondition for task verification scenarios.
225→ */
226→export async function createTaskWithCommit(
227→  surreal: Surreal,
228→  workspaceId: string,
229→  opts: CreateTaskWithCommitOptions,
230→): Promise<{ taskId: string; commitId: string; sha: string }> {
231→  const taskId = `task-${crypto.randomUUID()}`;
232→  const commitId = `commit-${crypto.randomUUID()}`;
233→  const sha = opts.sha ?? `abc${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
234→  const taskRecord = new RecordId("task", taskId);
235→  const commitRecord = new RecordId("git_commit", commitId);
236→  const workspaceRecord = new RecordId("workspace", workspaceId);
237→
238→  // Create the git_commit record (but NOT via CREATE if we want to avoid triggering commit_created EVENT)
239→  // Use a direct insert approach to seed without firing events
240→  await surreal.query(
241→    `CREATE $commit CONTENT $content;`,
242→    {
243→      commit: commitRecord,
244→      content: {
245→        sha,
246→        repository: opts.repository ?? "org/repo",
247→        message: `feat: ${opts.title}`,
248→        author_name: "test-agent",
249→        workspace: workspaceRecord,
250→        created_at: new Date(),
251→      },
252→    },
253→  );
254→
255→  // Create the task linked to the commit
256→  await surreal.query(
257→    `CREATE $task CONTENT $content;`,
258→    {
259→      task: taskRecord,
260→      content: {
261→        title: opts.title,
262→        description: opts.description ?? "Test task for observer verification",
263→        status: opts.status ?? "in_progress",
264→        source_commit: commitRecord,
265→        workspace: workspaceRecord,
266→        created_at: new Date(),
267→        updated_at: new Date(),
268→      },
269→    },
270→  );
271→
272→  return { taskId, commitId, sha };
273→}
