  2→ * Intent Node Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with intent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
  9→ *   POST /api/intents/:id/veto      (human veto)
 10→ *   MCP tools: create_intent, submit_intent, get_intent_status
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// Re-export everything from orchestrator-test-kit
 15→export {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  createTestProject,
 21→  getTestUserBearerToken,
 22→  fetchJson,
 23→  fetchRaw,
 24→  type OrchestratorTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithToken,
 27→  type TestWorkspace,
 28→  type TestTask,
 29→  type TestProject,
 30→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 31→
