 33→  fetchJson,
 34→  type TestUser,
 35→  type TestUserWithToken,
 36→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 37→
 38→// ---------------------------------------------------------------------------
 39→// Intent-Specific Types
 40→// ---------------------------------------------------------------------------
 41→
 42→export type IntentStatus =
 43→  | "draft"
 44→  | "pending_auth"
 45→  | "pending_veto"
 46→  | "authorized"
 47→  | "executing"
 48→  | "completed"
 49→  | "vetoed"
 50→  | "failed";
 51→
 52→export type ActionSpec = {
 53→  provider: string;
 54→  action: string;
 55→  params?: Record<string, unknown>;
 56→};
 57→
 58→export type BudgetLimit = {
 59→  amount: number;
 60→  currency: string;
 61→};
 62→
 63→export type EvaluationResult = {
 64→  decision: "APPROVE" | "REJECT";
 65→  risk_score: number;
 66→  reason: string;
 67→  evaluated_at: string;
 68→  policy_only: boolean;
 69→};
 70→
 71→export type IntentRecord = {
 72→  id: RecordId<"intent">;
 73→  goal: string;
 74→  reasoning: string;
 75→  status: IntentStatus;
 76→  priority: number;
 77→  action_spec: ActionSpec;
 78→  budget_limit?: BudgetLimit;
 79→  evaluation?: EvaluationResult;
 80→  veto_expires_at?: string;
 81→  veto_reason?: string;
 82→  error_reason?: string;
 83→  trace_id: RecordId<"trace">;
 84→  created_at: string;
 85→  updated_at?: string;
 86→};
 87→
 88→export type CreateIntentOptions = {
 89→  goal: string;
 90→  reasoning: string;
 91→  priority?: number;
 92→  action_spec: ActionSpec;
 93→  budget_limit?: BudgetLimit;
 94→  taskId?: string;
 95→};
