351→/**
352→ * Simulates the evaluation endpoint completing (for tests where the
353→ * SurrealQL EVENT may not fire in the test environment).
354→ * Directly updates the intent with an evaluation result and new status.
355→ */
356→export async function simulateEvaluation(
357→  surreal: Surreal,
358→  intentId: string,
359→  evaluation: {
360→    decision: "APPROVE" | "REJECT";
361→    risk_score: number;
362→    reason: string;
363→    policy_only?: boolean;
364→  },
365→  resultStatus: IntentStatus,
366→): Promise<void> {
367→  const intentRecord = new RecordId("intent", intentId);
368→  const evalContent = {
369→    decision: evaluation.decision,
370→    risk_score: evaluation.risk_score,
371→    reason: evaluation.reason,
372→    evaluated_at: new Date(),
373→    policy_only: evaluation.policy_only ?? false,
374→  };
375→
376→  const updates: Record<string, unknown> = {
377→    status: resultStatus,
378→    evaluation: evalContent,
379→    updated_at: new Date(),
380→  };
381→
382→  // If entering veto window, set expiry
383→  if (resultStatus === "pending_veto") {
384→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
385→    updates.veto_expires_at = expiresAt;
386→  }
387→
388→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
389→    intent: intentRecord,
390→    updates,
391→  });
392→}
393→
394→/**
395→ * Queries the identity record for a user to get the identity ID.
396→ * Needed because intent.requester links to identity, not user.
397→ */
398→export async function getIdentityId(
399→  surreal: Surreal,
400→): Promise<string> {
401→  const rows = (await surreal.query(
402→    `SELECT id FROM identity LIMIT 1;`,
403→  )) as Array<Array<{ id: RecordId<"identity"> }>>;
404→  const result = rows[0]?.[0];
405→  if (!result) {
406→    throw new Error("No identity found -- create a test user first");
407→  }
408→  return result.id.id as string;
409→}
410→
411→/**
412→ * Creates a test identity directly in the database.
413→ * Used when we need an identity record without going through auth.
414→ */
415→export async function createTestIdentity(
416→  surreal: Surreal,
417→  name: string,
418→  type: "human" | "agent" = "agent",
419→  workspaceId?: string,
420→): Promise<string> {
421→  const identityId = `id-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
422→  const identityRecord = new RecordId("identity", identityId);
423→
424→  const content: Record<string, unknown> = {
425→    name,
426→    type,
427→    created_at: new Date(),
428→  };
429→
430→  if (workspaceId) {
431→    content.workspace = new RecordId("workspace", workspaceId);
432→  }
433→
434→  await surreal.query(`CREATE $identity CONTENT $content;`, {
435→    identity: identityRecord,
436→    content,
437→  });
438→  return identityId;
439→}
440→
441→/**
442→ * Wires the SurrealQL EVENT that fires when an intent transitions to
443→ * pending_auth. The EVENT calls http::post to the real test server's
444→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
445→ *
446→ * Callback host can be overridden via INTENT_EVAL_CALLBACK_HOST.
447→ * Call this in beforeAll after the test server has booted.
448→ */
449→export async function wireIntentEvaluationEvent(
450→  surreal: Surreal,
451→  port: number,
452→): Promise<void> {
453→  const configuredHost = process.env.INTENT_EVAL_CALLBACK_HOST?.trim();
454→  const candidateHosts = configuredHost && configuredHost.length > 0
455→    ? [configuredHost]
456→    : ["127.0.0.1", "host.docker.internal"];
457→
458→  let baseUrl: string | undefined;
459→  let lastError = "";
460→
461→  for (const host of candidateHosts) {
462→    const candidateBaseUrl = `http://${host}:${port}`;
463→
464→    try {
465→      await surreal.query(`RETURN http::head($url);`, {
466→        url: `${candidateBaseUrl}/healthz`,
467→      });
468→      baseUrl = candidateBaseUrl;
469→      break;
470→    } catch (error) {
471→      lastError = error instanceof Error ? error.message : String(error);
472→    }
473→  }
474→
475→  if (!baseUrl) {
476→    throw new Error(
477→      `Unable to reach acceptance server from SurrealDB for intent callback. ` +
478→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
479→      `Last error: ${lastError}`,
480→    );
481→  }
482→
483→  await surreal.query(`
484→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
485→      ASYNC
486→      RETRY 3
487→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
488→      THEN {
489→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
490→      };
491→  `);
492→}
